const QUESTIONS_CPENT_C4 = [
  { id:90701, domain:4, level:1, question:"Which IEEE 802.11 amendment introduced operation in the 5 GHz band with OFDM at up to 54 Mbps?", options:["802.11a, which uses OFDM in the 5 GHz band and reaches a maximum data rate of 54 Mbps","802.11b, which uses DSSS in the 2.4 GHz band and reaches a maximum data rate of only 11 Mbps","802.11 legacy, which uses FHSS in the 2.4 GHz band and reaches only 2 Mbps maximum data rate","802.11g, which uses OFDM but operates only within the 2.4 GHz band at 54 Mbps maximum rate"], correct:0, explanation:"802.11a is the 5 GHz OFDM amendment at 54 Mbps; 802.11b and legacy use 2.4 GHz at lower rates and 802.11g stays in 2.4 GHz." },
  { id:90702, domain:4, level:1, question:"Which 802.11 amendment is branded as Wi-Fi 6 and operates in both the 2.4 GHz and 5 GHz bands?", options:["802.11ac, branded Wi-Fi 5, which operates only in the 5 GHz band using wider channel bonding widths","802.11ax, branded Wi-Fi 6, which uses OFDMA and operates across both the 2.4 and 5 GHz bands","802.11n, branded Wi-Fi 4, which introduced MIMO but predates the OFDMA scheduling technology used later","802.11ad, branded WiGig, which operates in the 60 GHz band for very short range high throughput links"], correct:1, explanation:"802.11ax (Wi-Fi 6) uses OFDMA in both bands; 802.11ac is 5 GHz only, 802.11n lacks OFDMA, and 802.11ad is 60 GHz." },
  { id:90703, domain:4, level:1, question:"In 802.11 terminology, what is the identifier clients use as the human-readable name of a wireless network?", options:["The BSSID, which is the MAC address of the access point radio rather than any human-readable label at all","The ESSID hash, a cryptographic digest computed only after the four-way handshake fully completes each time","The SSID, a human-readable network name advertised in beacon frames that clients use to identify a WLAN","The channel number, which merely indicates the radio frequency the access point is currently transmitting on"], correct:2, explanation:"The SSID is the human-readable network name; the BSSID is the AP MAC address and the channel is a frequency, not a name." },
  { id:90704, domain:4, level:2, question:"What fundamental weakness makes WEP encryption crackable within minutes using tools like aircrack-ng?", options:["Its use of AES in CBC mode leaks the key whenever more than one client associates to the same access point","Its reliance on Diffie-Hellman key exchange exposes the shared secret to any passive observer on the channel","Its dependence on certificate pinning fails because access points cannot validate the client supplicant chain","Its 24-bit IV space is too small, causing IV reuse that lets attackers recover the key from captured traffic"], correct:3, explanation:"WEP's 24-bit IV causes reuse enabling statistical key recovery; WEP uses RC4 not AES/DH and has no certificates." },
  { id:90705, domain:4, level:2, question:"Which technique accelerates WEP cracking by generating traffic to capture more initialization vectors quickly?", options:["The ARP replay attack, which reinjects captured ARP requests to force the AP to emit many new IV-bearing frames","The KRACK attack, which manipulates the four-way handshake to reinstall an all-zero pairwise transient key value","The Pixie Dust attack, which exploits weak entropy in the access point WPS registrar nonce generation routine","The PMKID attack, which requests the pairwise master key identifier directly from the very first EAPOL message"], correct:0, explanation:"ARP replay reinjects ARP frames to speed IV collection for WEP; KRACK, Pixie Dust, and PMKID target WPA2/WPS, not WEP." },
  { id:90706, domain:4, level:2, question:"What must an attacker capture to perform an offline dictionary attack against a WPA2-PSK network?", options:["The full unencrypted payload of every data frame the client sends after it has authenticated successfully","The four-way handshake EAPOL frames exchanged between the client and access point during association setup","The RADIUS shared secret configured between the access point and the enterprise authentication back-end server","The DHCP lease offer and acknowledgement packets that assign the client its internal IP address on the LAN"], correct:1, explanation:"The four-way handshake EAPOL frames hold material for offline PSK cracking; data payloads, RADIUS secrets, and DHCP are irrelevant." },
  { id:90707, domain:4, level:2, question:"Which tool is commonly used to capture the WPA2 four-way handshake by forcing a client to reauthenticate?", options:["ettercap, which is designed primarily for ARP-based man-in-the-middle attacks on switched Ethernet segments","sqlmap, which automates detection and exploitation of SQL injection flaws in backend web applications only","aireplay-ng, which sends deauthentication frames so the client reconnects and its handshake can be captured","responder, which poisons LLMNR and NBT-NS name resolution to capture NetNTLM hashes on a local network"], correct:2, explanation:"aireplay-ng sends deauth frames to trigger a fresh handshake for capture; ettercap, sqlmap, and responder target other layers." },
  { id:90708, domain:4, level:3, question:"After capturing a WPA2 handshake, which tool can crack the passphrase using GPU acceleration and mode 22000?", options:["Wireshark, which can display the captured EAPOL frames but has no built-in passphrase cracking capability","Nmap, which discovers hosts and open ports but does not perform any wireless passphrase recovery at all","Metasploit, which is an exploitation framework and does not natively brute force WPA2 handshake material","hashcat, which cracks the WPA2 handshake or PMKID with GPU acceleration using its 22000 hash mode format"], correct:3, explanation:"hashcat mode 22000 cracks WPA2 handshakes/PMKID on GPUs; Wireshark only displays, Nmap scans, and Metasploit exploits." },
  { id:90709, domain:4, level:3, question:"What does the WPA2 four-way handshake derive from the PMK and the exchanged client and AP nonces?", options:["The pairwise transient key used to encrypt unicast traffic between the client and the access point","The group master key that is shared identically across every client that authenticates to the same SSID","The RADIUS accounting session identifier used to bill enterprise wireless usage back to each department","The WPS device password that authorizes push-button registration of new stations onto the wireless network"], correct:0, explanation:"The handshake derives the PTK from the PMK and nonces; the group key is separate and WPS/RADIUS IDs are unrelated." },
  { id:90710, domain:4, level:3, question:"What makes the PMKID attack against WPA2 notable compared to traditional four-way handshake capture?", options:["It decrypts all previously captured traffic instantly by exploiting a backdoor in the RC4 stream cipher design","It can obtain crackable material from a single EAPOL frame without needing any connected client to be deauthenticated","It bypasses the passphrase entirely by injecting a forged group temporal key into the access point memory space","It requires physical access to the access point serial console to dump the stored pre-shared key material out"], correct:1, explanation:"PMKID needs only one frame from the AP and no client, unlike handshake capture; it still requires offline PSK cracking." },
  { id:90711, domain:4, level:3, question:"The KRACK vulnerability exploits which specific weakness in the WPA2 protocol?", options:["A hardcoded default master key present in every access point firmware image shipped by all major vendors","An integer overflow in the beacon interval field that lets attackers crash the client supplicant remotely","Reinstallation of an already-in-use key during handshake retransmission, resetting nonces and replay counters","The absence of any message integrity check on management frames sent before association fully completes"], correct:2, explanation:"KRACK forces key reinstallation, resetting nonces to enable replay/decryption; it is not a default key, overflow, or MIC issue." },
  { id:90712, domain:4, level:2, question:"What distinguishes an evil twin attack from a simple rogue access point?", options:["A rogue access point always uses WPA3 encryption while an evil twin is restricted to open authentication only","An evil twin can only be deployed by the network owner during authorized penetration testing engagements","A rogue access point requires a wired uplink whereas an evil twin never forwards any client traffic at all","An evil twin clones a legitimate SSID and often its BSSID to lure clients that trust the real network"], correct:3, explanation:"An evil twin impersonates a trusted SSID/BSSID to lure clients; a rogue AP is simply an unauthorized AP, not necessarily a clone." },
  { id:90713, domain:4, level:2, question:"Which technique is used to force clients off a legitimate AP so they associate with an evil twin instead?", options:["Sending 802.11 deauthentication frames to disconnect clients, which then reconnect to the stronger rogue signal","Flooding the DHCP pool so no client can obtain an address from the legitimate access point going forward","Poisoning the upstream DNS resolver so the legitimate SSID name fails to resolve for associated stations","Overwriting the client wireless driver so it permanently forgets every previously saved network profile it had"], correct:0, explanation:"Deauth frames drop clients so they reassociate with the evil twin; DHCP exhaustion and DNS poisoning do not sever the RF association." },
  { id:90714, domain:4, level:2, question:"Why are 802.11 deauthentication frames easy to spoof in networks that do not deploy 802.11w?", options:["They are encrypted with the group temporal key that every associated client already possesses and can reuse","Management frames are unauthenticated by default, so any device can forge them using a spoofed source address","They require a valid RADIUS token that access points cache and then freely share with any requesting station","They contain a sequence number verified against a blockchain ledger that attackers can trivially rewrite later"], correct:1, explanation:"Without 802.11w (PMF) management frames are unauthenticated and forgeable; they are not encrypted or RADIUS/blockchain protected." },
  { id:90715, domain:4, level:2, question:"Which 802.11 amendment adds Protected Management Frames to defend against deauthentication attacks?", options:["802.11r, which speeds fast BSS transition roaming but provides no protection for management frames at all","802.11k, which supplies radio resource measurement reports and has no bearing on frame authentication itself","802.11w, which adds Protected Management Frames to authenticate deauthentication and disassociation messages","802.11e, which introduces quality of service prioritization and does not secure management frames in any way"], correct:2, explanation:"802.11w (PMF) authenticates management frames to stop deauth spoofing; 802.11r/k/e address roaming, measurement, and QoS." },
  { id:90716, domain:4, level:2, question:"What weakness does the original WPS PIN method suffer from that enables efficient brute-force attacks?", options:["The PIN is transmitted in cleartext over the air, letting any passive listener read it from a single beacon frame","The PIN rotates every second, so attackers must synchronize atomic clocks to have any chance of guessing it right","The PIN is derived from the AP serial number, which is never printed on the device label for privacy reasons ever","The eight-digit PIN is validated in two halves, cutting the effective keyspace to roughly eleven thousand tries"], correct:3, explanation:"WPS validates the PIN in two halves (last digit a checksum), shrinking the keyspace dramatically; it is not sent in cleartext." },
  { id:90717, domain:4, level:3, question:"The Pixie Dust attack against WPS succeeds because of which implementation flaw?", options:["Weak or predictable randomness in the registrar nonces, letting the PIN be recovered offline from one exchange","A buffer overflow in the EAP-WSC parser that grants the attacker a root shell on the access point directly","A hardcoded WPS PIN of 12345670 that vendors were contractually required to ship on every consumer router","The lack of any lockout mechanism, which alone allows unlimited online guessing without offline computation"], correct:0, explanation:"Pixie Dust exploits poor nonce entropy to derive the PIN offline; it is not an overflow, a hardcoded PIN, or merely a lockout gap." },
  { id:90718, domain:4, level:2, question:"Which tool automates the full wireless auditing workflow, chaining scanning, deauthentication, and cracking?", options:["Hydra, which performs online brute-force attacks against network login services rather than wireless radios","Wifite, which automates scanning, capturing handshakes, and launching WEP, WPA, and WPS attacks in one workflow","John the Ripper, which cracks password hashes offline but does not interact with wireless radios directly at all","Aircrack-ng alone, which cracks captured keys but does not orchestrate scanning and deauth automatically for you"], correct:1, explanation:"Wifite orchestrates the full wireless attack chain; Hydra and John target logins/hashes and aircrack-ng alone only cracks captured data." },
  { id:90719, domain:4, level:1, question:"What is the primary role of Kismet in wireless penetration testing?", options:["An active injector that floods the channel with deauthentication frames to disconnect every nearby client at once","A GPU cracking engine optimized for recovering WPA3 SAE passphrases from captured commit messages offline","A passive detector and sniffer that discovers networks and clients, including hidden SSIDs, without transmitting","A rogue access point framework that automatically clones enterprise portals to harvest user credentials only"], correct:2, explanation:"Kismet passively detects networks/clients and can reveal hidden SSIDs; it does not inject, crack, or host rogue portals." },
  { id:90720, domain:4, level:1, question:"Which mode must a wireless adapter support to capture all 802.11 frames regardless of their destination?", options:["Managed mode, which restricts the adapter to receiving only frames addressed to its own associated BSSID","Master mode, which turns the adapter into an access point that beacons an SSID for clients to join it directly","Ad-hoc mode, which forms a peer-to-peer network but still filters out frames not intended for the station","Monitor mode, which lets the adapter capture all frames on a channel without associating to any network"], correct:3, explanation:"Monitor mode captures all frames on a channel; managed mode filters to the associated BSSID and master/ad-hoc serve other roles." },
  { id:90721, domain:4, level:3, question:"Which WPA3 feature replaces the WPA2 pre-shared key handshake to resist offline dictionary attacks?", options:["Simultaneous Authentication of Equals, which uses a dragonfly handshake resistant to offline guessing attacks","A rotating WEP-style initialization vector that is now expanded to 128 bits to prevent any reuse collisions","A mandatory RADIUS server requirement that eliminates pre-shared keys from all personal mode deployments","A static per-vendor master secret embedded in firmware that removes the need for any client authentication"], correct:0, explanation:"WPA3-Personal uses SAE (dragonfly) to resist offline dictionary attacks; it is not a WEP IV, mandatory RADIUS, or embedded secret." },
  { id:90722, domain:4, level:2, question:"What does a bluesnarfing attack accomplish against a vulnerable Bluetooth device?", options:["Sending unsolicited anonymous text or business-card messages to nearby discoverable Bluetooth devices only","Unauthorized access to data such as contacts and messages by exploiting flaws in the OBEX push service","Overloading the device radio with pairing requests until its battery is fully drained and it powers off cold","Cloning the device MAC address to impersonate it on the local Wi-Fi network for lateral movement later on"], correct:1, explanation:"Bluesnarfing steals data via OBEX flaws; sending unsolicited messages is bluejacking, and the others describe DoS or spoofing." },
  { id:90723, domain:4, level:2, question:"How does bluejacking differ from bluesnarfing?", options:["Bluejacking steals the pairing keys whereas bluesnarfing only pushes advertising content onto the screen","Bluejacking works over BLE exclusively while bluesnarfing is limited to classic Bluetooth BR/EDR devices","Bluejacking merely sends unsolicited messages to a device, while bluesnarfing extracts data without consent","Bluejacking requires prior pairing while bluesnarfing can only run against already-trusted bonded devices"], correct:2, explanation:"Bluejacking sends unsolicited messages; bluesnarfing steals data. The other options invert or overstate the technical constraints." },
  { id:90724, domain:4, level:2, question:"In Bluetooth Low Energy, what does a pen tester examine to understand a device's exposed data and functions?", options:["The WEP keystream, which BLE reuses from legacy Wi-Fi to protect its advertising and connection channels","The Modbus register map, which BLE peripherals expose so industrial controllers can poll sensor readings","The DHCP option list, which BLE devices broadcast to negotiate IP addresses before any data is exchanged","The GATT profile, which organizes services and characteristics that clients read, write, or subscribe to"], correct:3, explanation:"BLE exposes services/characteristics via the GATT profile; WEP, Modbus registers, and DHCP options are unrelated to BLE structure." },
  { id:90725, domain:4, level:2, question:"Which attack against RFID access badges involves reading a legitimate card and replaying its data?", options:["Cloning, where the attacker captures a card UID or data and writes it to a blank tag to impersonate it","Jamming, where the attacker floods the reader frequency so no legitimate badge can ever be read again","Phishing, where the attacker emails the badge holder a link that silently reprograms the physical card","Fuzzing, where the attacker sends malformed TCP packets to the door controller until the lock disengages"], correct:0, explanation:"RFID cloning copies a card's data to a blank tag to impersonate it; jamming is DoS and phishing/fuzzing target other layers." },
  { id:90726, domain:4, level:2, question:"What is a common security weakness of low-frequency 125 kHz RFID proximity cards?", options:["They enforce mutual TLS between card and reader, which attackers defeat only with a valid CA private key","They often transmit a static unencrypted identifier that can be captured and cloned with inexpensive readers","They rotate a 256-bit AES session key each read, so cloning requires breaking modern symmetric cryptography","They store biometric templates that must be matched against a fingerprint before the credential is emitted"], correct:1, explanation:"125 kHz proximity cards usually emit a static, unencrypted ID that is trivial to clone; they lack TLS, rotating keys, or biometrics." },
  { id:90727, domain:4, level:2, question:"Which layer of a typical IoT architecture is most directly targeted by physical hardware tampering?", options:["The cloud application layer, which runs entirely in remote data centers far from any physical attacker reach","The network transport layer, which exists only as logical protocol state and has no physical components at all","The perception or device layer, where sensors and actuators and their exposed debug ports reside physically","The business analytics layer, which processes aggregated data and is unreachable by hardware-level attacks"], correct:2, explanation:"The perception/device layer holds the physical hardware and debug ports targeted by tampering; cloud and analytics layers are remote/logical." },
  { id:90728, domain:4, level:1, question:"Which best describes the attack surface expansion introduced by large IoT deployments?", options:["A single hardened gateway that consolidates all traffic and eliminates every legacy protocol from the network","A reduction in endpoints because sensors report only to one central mainframe over an air-gapped serial link","An entirely cloud-native fabric with no physical devices, removing hardware attack vectors from consideration","Numerous low-power devices with weak defaults, limited patching, and exposed physical and network interfaces"], correct:3, explanation:"IoT expands attack surface through many weakly-defended devices with physical/network exposure; it does not shrink or eliminate endpoints." },
  { id:90729, domain:4, level:2, question:"Which tool is most commonly used to identify and extract file systems embedded in an IoT firmware image?", options:["binwalk, which signature-scans firmware images to identify and carve out embedded file systems and archives","nikto, which scans web servers for known vulnerable scripts but cannot parse binary firmware image contents","hping3, which crafts custom TCP/IP packets for network testing and has no firmware carving capability at all","enum4linux, which enumerates SMB shares and users on Windows hosts rather than extracting firmware contents"], correct:0, explanation:"binwalk carves embedded filesystems from firmware; nikto scans web apps, hping3 crafts packets, and enum4linux enumerates SMB." },
  { id:90730, domain:4, level:2, question:"After extracting an IoT firmware file system, what is a high-value target a pen tester searches for?", options:["The physical dimensions of the flash chip, which reveal the manufacturing plant that produced the device unit","Hardcoded credentials, private keys, and API tokens left inside configuration files and binaries in the image","The retail box artwork strings, which occasionally contain the vendor marketing slogan in several languages","The ambient operating temperature range, which is stored so the CPU can throttle under thermal stress events"], correct:1, explanation:"Extracted firmware often yields hardcoded secrets and keys; chip dimensions, box art, and temperature ranges are not exploitable secrets." },
  { id:90731, domain:4, level:3, question:"What technique lets a tester run and interact with extracted firmware without the physical device present?", options:["Firmware signing, which cryptographically seals the image so it can only run on the original hardware unit","Firmware over-the-air update, which pushes a new image to the device rather than running the current one","Firmware emulation, using tools like QEMU or FirmAE to execute the binaries and services on a host system","Firmware attestation, which reports a measured hash to a remote server without executing any code at all"], correct:2, explanation:"Emulation (QEMU/FirmAE) runs firmware without hardware; signing, OTA updates, and attestation do not provide an interactive runtime." },
  { id:90732, domain:4, level:2, question:"Which hardware interface is most commonly used to obtain a serial console shell on an IoT device?", options:["HDMI, whose differential video pairs carry display output and cannot present any interactive shell prompt","USB-C power delivery, which negotiates charging voltage only and never exposes a command interpreter at all","The Ethernet magnetics, which isolate the physical layer and provide no direct console access to the firmware","UART, whose transmit, receive, and ground pins often expose an unauthenticated bootloader or shell prompt"], correct:3, explanation:"UART commonly exposes a serial console/bootloader; HDMI carries video, USB-C PD negotiates power, and Ethernet magnetics isolate signals." },
  { id:90733, domain:4, level:3, question:"What is the primary purpose of the JTAG interface from a hardware hacking perspective?", options:["Boundary-scan and on-chip debugging that can read and write memory and halt the processor for deep analysis","Streaming high-definition video from the device camera sensor directly to an external capture card device","Supplying regulated three-point-three volt power to peripheral chips mounted elsewhere on the circuit board","Broadcasting the device MAC address over the air so nearby access points can pre-authorize its association"], correct:0, explanation:"JTAG enables on-chip debug and memory read/write; it is a debug/test bus, not a video, power, or wireless interface." },
  { id:90734, domain:4, level:3, question:"Which interface would a tester tap to intercept communication between a microcontroller and a flash chip?", options:["VGA, an analog video standard used to drive external monitors and unrelated to inter-chip flash access at all","SPI, the serial bus over which many microcontrollers read from and write to external flash memory chips","PS/2, a legacy keyboard and mouse connector that carries human input rather than any memory bus traffic","RS-485, a multidrop differential bus used mainly for long-distance industrial serial links between nodes"], correct:1, explanation:"SPI links microcontrollers to external flash and can be tapped; VGA/PS-2 are peripheral I/O and RS-485 is a long-haul serial bus." },
  { id:90735, domain:4, level:2, question:"What is a frequent misconfiguration in MQTT deployments that a pen tester should test for?", options:["Brokers requiring client certificates signed by two independent certificate authorities before any publish","Brokers that encrypt every payload with per-topic AES keys rotated on each individual message delivery event","Brokers allowing anonymous connections and unrestricted topic subscription, exposing all published messages","Brokers that reject all wildcard subscriptions and mandate mutual TLS for both publishers and subscribers"], correct:2, explanation:"Many MQTT brokers allow anonymous access and open subscriptions, leaking messages; the other options describe strong, uncommon hardening." },
  { id:90736, domain:4, level:1, question:"Which protocol is a lightweight UDP-based alternative to HTTP designed for constrained IoT devices?", options:["SMTP, the Simple Mail Transfer Protocol, which is a heavyweight TCP email protocol unsuited to tiny nodes","LDAP, the directory access protocol used to query enterprise user and group objects over persistent links","BGP, the border gateway protocol that exchanges routing reachability information between autonomous systems","CoAP, the Constrained Application Protocol, which runs over UDP and mirrors REST semantics for tiny devices"], correct:3, explanation:"CoAP is the UDP, REST-like protocol for constrained devices; SMTP, LDAP, and BGP serve email, directory, and routing respectively." },
  { id:90737, domain:4, level:3, question:"Why can CoAP running over UDP be abused in amplification denial-of-service attacks?", options:["Spoofed small requests can trigger much larger responses sent to the forged victim address over connectionless UDP","Its mandatory TCP three-way handshake forces the victim to complete thousands of expensive connection setups","It requires the server to store a full session for each client, exhausting memory after only a few requests","Its built-in TLS renegotiation loop consumes the victim CPU by repeatedly re-deriving the master secret each time"], correct:0, explanation:"CoAP over UDP allows spoofed-source amplification because responses exceed requests; it is connectionless, so there is no TCP handshake to blame." },
  { id:90738, domain:4, level:1, question:"Which issue tops the OWASP IoT Top 10 as the most pervasive IoT security problem?", options:["Excessive use of hardware security modules that overwhelm low-power devices and drain their batteries fast","Weak, guessable, or hardcoded passwords that ship as defaults and are rarely changed by device owners later","Overly aggressive certificate pinning that blocks legitimate firmware updates from reaching the devices later","Mandatory multi-factor authentication that frustrates users and pushes them toward insecure workarounds"], correct:1, explanation:"Weak/hardcoded default passwords lead the OWASP IoT Top 10; the distractors describe overly strong controls, not real top risks." },
  { id:90739, domain:4, level:1, question:"What service does Shodan provide that is valuable during IoT reconnaissance?", options:["A cloud sandbox that detonates suspicious firmware images and returns a malware verdict within a few seconds","A brute-force cracking farm that recovers WPA2 passphrases from uploaded handshake captures on demand fast","A search engine indexing internet-exposed devices and their banners, revealing exposed IoT services worldwide","A certificate authority that issues free short-lived TLS certificates specifically for IoT device gateways only"], correct:2, explanation:"Shodan indexes internet-exposed devices/banners for reconnaissance; it is not a sandbox, cracking farm, or certificate authority." },
  { id:90740, domain:4, level:2, question:"A tester finds an IoT admin panel reachable from the internet with the login admin/admin. Which OWASP IoT category fits?", options:["Insufficient privacy protection, which concerns unnecessary collection and exposure of personal user data","Lack of physical hardening, which concerns exposed debug ports and removable storage on the device chassis","Insecure data transfer, which concerns unencrypted communication channels rather than credential strength","Insecure default settings combined with weak default credentials that were never altered before deployment"], correct:3, explanation:"admin/admin plus internet exposure is insecure defaults/weak credentials; privacy, physical, and transfer categories describe different flaws." },
  { id:90741, domain:4, level:1, question:"In an ICS environment, what is the primary function of a PLC?", options:["A ruggedized controller that executes logic to read sensor inputs and drive actuators in real time","A relational database server that archives years of historian data for regulatory reporting purposes only","A human operator workstation that renders graphical dashboards for supervisory monitoring of the process","A perimeter firewall appliance that segments the corporate IT network from the internet-facing DMZ zone"], correct:0, explanation:"A PLC executes control logic driving actuators from sensor inputs; historians, HMIs, and firewalls are separate ICS components." },
  { id:90742, domain:4, level:1, question:"Within ICS terminology, what role does the HMI serve?", options:["A programmable logic controller that directly executes ladder logic against field sensors and actuators","A human-machine interface that visualizes process state and lets operators issue supervisory commands","A remote terminal unit that gathers telemetry from geographically dispersed substations over serial links","A distributed control node that autonomously regulates a continuous process without any operator display"], correct:1, explanation:"The HMI visualizes process state for operators; PLCs run logic, RTUs gather remote telemetry, and DCS nodes regulate processes." },
  { id:90743, domain:4, level:2, question:"What is the defining characteristic of an RTU compared to a PLC in SCADA systems?", options:["An RTU is a graphical operator console that always sits in the central control room next to the servers","An RTU is a general-purpose IT database appliance that stores historian trends for long-term compliance","An RTU is optimized for remote, geographically dispersed sites and rugged telemetry over wide-area links","An RTU is a corporate email relay hardened to run inside the industrial DMZ between the IT and OT zones"], correct:2, explanation:"RTUs specialize in remote telemetry over wide areas; they are not operator consoles, databases, or email relays." },
  { id:90744, domain:4, level:2, question:"Which industrial protocol is well known for having no built-in authentication, a common pen-test target?", options:["Kerberos, which is a strongly authenticated ticket-based protocol used in enterprise IT domains rather than OT","IPsec, which provides authenticated and encrypted tunnels and is designed specifically to prevent tampering","SSHv2, which offers mutually authenticated encrypted channels widely used for secure remote administration","Modbus, an early industrial protocol that transmits register reads and writes with no authentication or encryption"], correct:3, explanation:"Modbus lacks authentication and encryption, a classic OT weakness; Kerberos, IPsec, and SSH are authenticated/encrypted protocols." },
  { id:90745, domain:4, level:2, question:"What is the purpose of the Purdue Enterprise Reference Architecture model in OT security?", options:["It defines hierarchical levels segmenting enterprise IT from control and process networks to guide defense","It specifies the exact ladder logic instructions that every certified PLC vendor must implement identically","It mandates a single flat network so every industrial device can reach every other device without filtering","It is a cryptographic key exchange standard used to secure Modbus communications between PLCs and RTUs"], correct:0, explanation:"The Purdue model layers IT/OT into segmented levels to guide defense; it is not a PLC instruction set, flat network, or crypto standard." },
  { id:90746, domain:4, level:3, question:"Why is air-gapping alone considered an insufficient security control for modern ICS networks?", options:["Air gaps encrypt all industrial traffic so strongly that operators can no longer troubleshoot the process","Air gaps are frequently bridged by removable media, remote maintenance links, and transient contractor laptops","Air gaps require every PLC to run a full antivirus agent that consumes the limited controller CPU budget","Air gaps automatically expose the SCADA historian to the internet whenever a patch cycle is scheduled to run"], correct:1, explanation:"Air gaps are routinely bridged by USB media, vendor links, and laptops, so they are not absolute; the other statements are false." },
  { id:90747, domain:4, level:2, question:"Which consideration is uniquely critical when penetration testing an operational technology environment?", options:["Maximizing scan speed, because OT devices tolerate aggressive fuzzing far better than fragile IT web servers","Ignoring change control, because OT systems are rebuilt nightly and any disruption self-heals by morning again","Safety and availability, because active scanning or exploits can disrupt physical processes and endanger people","Prioritizing confidentiality over everything, because OT data secrecy always outweighs keeping the plant running"], correct:2, explanation:"OT testing must prioritize safety/availability since disruptions harm physical processes; OT devices are fragile, not scan-tolerant." },
  { id:90748, domain:4, level:2, question:"Which protocol was designed for electric utility SCADA and adds time-stamped events over serial and IP?", options:["HTTP, the stateless web protocol used for browsers and REST APIs but not designed for utility SCADA telemetry","SNMP, a network device management protocol that polls counters rather than carrying utility process control data","FTP, a file transfer protocol that moves bulk files and has no concept of time-stamped SCADA event reporting","DNP3, widely used in electric and water utilities, supporting time-stamped events and unsolicited responses"], correct:3, explanation:"DNP3 is the utility SCADA protocol with time-stamped events; HTTP, SNMP, and FTP serve web, device management, and file transfer." },
  { id:90749, domain:4, level:2, question:"The S7 protocol that a pen tester might target is associated with which vendor's PLCs?", options:["Siemens, whose SIMATIC S7 controllers communicate using the proprietary S7comm protocol over TCP port 102","Cisco, whose enterprise routers use S7 as an internal routing protocol between distribution layer switches","Oracle, whose database clusters use S7 to replicate transaction logs between geographically separate nodes","VMware, whose hypervisors use S7 to migrate running virtual machines between hosts in a compute cluster"], correct:0, explanation:"S7comm is Siemens' SIMATIC PLC protocol on TCP/102; it has nothing to do with Cisco routing, Oracle replication, or VMware migration." },
  { id:90750, domain:4, level:2, question:"What does Profinet primarily provide in an industrial automation network?", options:["A public-key infrastructure that issues operator smart-card certificates for badge access to control rooms","Real-time Ethernet-based communication between controllers and field devices in factory automation systems","A cloud analytics dashboard that aggregates plant KPIs for executives viewing them from corporate offices","A wireless mesh protocol used by battery-powered sensors to report readings over multi-year deployments"], correct:1, explanation:"Profinet is real-time industrial Ethernet between controllers and field devices; it is not a PKI, dashboard, or wireless mesh." },
  { id:90751, domain:4, level:3, question:"In a Modbus penetration test, what does a 'write single coil' function code let an attacker potentially do?", options:["Retrieve the full firmware image of the controller for offline reverse engineering of its ladder logic later","Establish an encrypted management tunnel to the PLC that bypasses the plant's network segmentation controls","Change a discrete output state on the target device, which could toggle a physical relay or actuator remotely","Enumerate the Windows domain accounts cached on the engineering workstation connected to the same switch"], correct:2, explanation:"Writing a coil changes a discrete output, potentially actuating hardware; it does not dump firmware, tunnel, or enumerate domain accounts." },
  { id:90752, domain:4, level:1, question:"What is a DCS in the context of process control?", options:["A dedicated cryptographic server that signs every firmware update pushed to field controllers in the plant","A disaster containment shelter that houses backup operators during a physical breach of the control room","A data compression standard applied to historian archives before they are written to long-term cold storage","A distributed control system where controllers are spread across a plant to regulate continuous processes"], correct:3, explanation:"A DCS distributes controllers across a plant for continuous process regulation; it is not a crypto server, shelter, or compression standard." },
  { id:90753, domain:4, level:2, question:"What information does a hidden SSID network still reveal that lets attackers discover its name?", options:["The SSID appears in probe request and association frames when clients connect, exposing the cloaked name","The SSID is embedded in the WPA2 group key, so cracking any single data frame instantly reveals the name","The SSID is printed in cleartext inside every ICMP echo reply the access point sends to connected clients","The SSID is broadcast in a special DNS TXT record that any resolver on the internet can query anonymously"], correct:0, explanation:"Client probe/association frames leak a hidden SSID; it is not stored in the group key, ICMP replies, or public DNS records." },
  { id:90754, domain:4, level:2, question:"Which frequency band offers more non-overlapping channels and less congestion for 802.11 networks?", options:["The 900 MHz band, which is the primary Wi-Fi band offering dozens of clean wide channels for clients","The 5 GHz band, which offers many more non-overlapping channels than the crowded three found in 2.4 GHz","The 2.4 GHz band, which despite its narrow width provides more non-overlapping channels than 5 GHz does","The 60 GHz band, which penetrates walls better than 5 GHz and thus is preferred for whole-home coverage"], correct:1, explanation:"5 GHz has far more non-overlapping channels than 2.4 GHz's three; 900 MHz is not standard Wi-Fi and 60 GHz has poor wall penetration." },
  { id:90755, domain:4, level:2, question:"What is the purpose of a captive portal often paired with an evil twin attack?", options:["To transparently encrypt all victim traffic with WPA3 so the attacker cannot be blamed for interception later","To automatically patch the victim wireless driver, closing the very vulnerability that enabled the attack itself","To present a fake login or credential page after the victim connects, harvesting entered usernames and passwords","To rate-limit the victim connection so slowly that they disconnect before any data can be captured at all"], correct:2, explanation:"A captive portal on an evil twin harvests credentials via a fake page; it does not protect, patch, or throttle the victim beneficially." },
  { id:90756, domain:4, level:2, question:"Which is a rogue access point risk even when the attacker performs no encryption cracking at all?", options:["The rogue AP automatically rekeying WPA3 for the entire enterprise, strengthening security without approval","The rogue AP forcing all corporate switches into monitor mode, which improves visibility for the defenders","The rogue AP issuing valid enterprise certificates to guests, seamlessly onboarding them to the secure VLAN","Employees connecting to an unauthorized AP that bridges the corporate network, bypassing perimeter controls"], correct:3, explanation:"A rogue AP can bridge the corporate network and bypass perimeter controls; the distractors falsely frame it as beneficial." },
  { id:90757, domain:4, level:3, question:"Why does capturing a WPA2 handshake not by itself reveal the network passphrase?", options:["The handshake only proves knowledge of the key; the passphrase must still be recovered through offline guessing","The handshake contains the passphrase in plaintext but is discarded by capture tools before it reaches disk","The handshake is encrypted with the passphrase, so decrypting it trivially prints the passphrase in cleartext","The handshake includes a decryption oracle that returns the passphrase after exactly one thousand queries sent"], correct:0, explanation:"The handshake enables offline guessing but never contains the passphrase directly; it is not plaintext or an oracle." },
  { id:90758, domain:4, level:2, question:"What is the role of a WiFi Pineapple in wireless penetration testing?", options:["A hardware WPA3 accelerator that legitimately strengthens enterprise wireless authentication for defenders","A purpose-built platform for rogue AP, evil twin, and man-in-the-middle wireless attacks in one appliance","A passive spectrum analyzer that only measures RF interference and cannot transmit any frames whatsoever","A certified RADIUS server appliance used to centralize enterprise 802.1X authentication for large campuses"], correct:1, explanation:"The WiFi Pineapple is a rogue-AP/MitM attack platform; it is not a defensive accelerator, passive analyzer, or RADIUS server." },
  { id:90759, domain:4, level:3, question:"Which attack targets 802.1X enterprise wireless by impersonating the RADIUS server to capture credentials?", options:["A WEP IV replay attack that reinjects ARP frames to gather enough IVs to statistically recover the key","A Pixie Dust attack that exploits weak WPS registrar nonce entropy to derive the router PIN offline fast","An evil twin with a fake RADIUS backend that captures MSCHAPv2 challenge-response hashes from clients","A Modbus write-coil injection that toggles a discrete output on the authentication server host controller"], correct:2, explanation:"Impersonating RADIUS captures MSCHAPv2 hashes from enterprise clients; WEP replay, Pixie Dust, and Modbus target other systems." },
  { id:90760, domain:4, level:2, question:"What does static analysis of an IoT firmware binary typically look for?", options:["The real-time power draw of the device under peak load, measured with an inline current probe on the board","The mechanical resonance frequency of the enclosure, useful only for acoustic side-channel experiments later","The retail supply-chain shipping route, reconstructed from timestamps embedded in the packaging barcodes","Vulnerable function calls, hardcoded secrets, and dangerous logic without ever executing the code at all"], correct:3, explanation:"Static analysis inspects code for vulnerable calls and secrets without running it; power draw, resonance, and shipping are not code properties." },
  { id:90761, domain:4, level:2, question:"Which is a common insecure update mechanism weakness in IoT devices?", options:["Firmware updates delivered over plaintext HTTP without signature verification, allowing malicious images","Firmware updates requiring a hardware security module signature validated by three independent authorities","Firmware updates that refuse to install unless the device measures a matching TPM attestation quote first","Firmware updates delivered only via physically removable media that a technician must insert on-site each time"], correct:0, explanation:"Unsigned firmware over plaintext HTTP lets attackers push malicious images; the distractors describe robust or restrictive controls." },
  { id:90762, domain:4, level:2, question:"A pen tester connects to an IoT device's exposed Telnet service. What is the most likely quick win?", options:["Decrypting the Telnet session with a captured TLS private key extracted from the device certificate store","Logging in with well-known default credentials that the vendor never forced the owner to change at setup","Exploiting a buffer overflow in the Telnet banner that immediately grants a signed kernel driver install","Bypassing multi-factor authentication that the Telnet daemon enforces before any command can be issued"], correct:1, explanation:"Default credentials are the classic Telnet quick win on IoT; Telnet is unencrypted (no TLS) and rarely enforces MFA." },
  { id:90763, domain:4, level:2, question:"What is the security concern with an IoT device using a hardcoded cryptographic key across all units?", options:["Each device generates a unique key at manufacture, so extraction affects only that single physical unit ever","The shared key rotates hourly across the fleet, so any extracted value is useless within sixty minutes flat","Extracting the key from one device compromises every other device that shares the same embedded secret","The key is stored only in a tamper-proof enclave that erases itself the instant any probe touches the die"], correct:2, explanation:"A hardcoded shared key means one extraction breaks the whole fleet; that contradicts unique per-device or rotating keys." },
  { id:90764, domain:4, level:3, question:"Why is patching often delayed or avoided on ICS/OT systems compared to IT systems?", options:["OT systems patch instantly and reboot without impact, so administrators simply forget to schedule updates","OT vendors release patches hourly, overwhelming teams who then choose to skip them out of sheer fatigue","OT devices reject all patches cryptographically unless signed by the plant operator's personal private key","Uptime and vendor certification requirements mean patches can void support or disrupt critical processes"], correct:3, explanation:"OT patching is delayed by uptime needs and vendor certification constraints; OT systems are not trivially patchable or hourly-updated." },
  { id:90765, domain:4, level:3, question:"What is a safety instrumented system (SIS) designed to do in an industrial plant?", options:["Independently bring the process to a safe state when hazardous conditions exceed predefined safety limits","Serve as the primary control loop that operators use for routine day-to-day adjustment of the process itself","Provide the corporate email and file-sharing services for engineers working inside the plant control room","Encrypt all historian archives before they are transmitted to the offsite disaster recovery data center"], correct:0, explanation:"An SIS independently trips the process to a safe state on hazards; it is separate from routine control, IT services, or archiving." },
  { id:90766, domain:4, level:3, question:"Which reconnaissance approach is the safest first step against a live OT network?", options:["Immediately launching an aggressive full-port SYN scan with maximum timing to enumerate hosts the fastest","Passive traffic monitoring and asset inventory to avoid disrupting fragile devices before any active testing","Fuzzing every discovered Modbus function code in parallel to quickly map which registers are writable now","Rebooting each PLC in sequence to observe which processes fail, mapping dependencies through disruption"], correct:1, explanation:"Passive monitoring first avoids disrupting fragile OT devices; aggressive scans, fuzzing, and reboots risk process disruption." },
  { id:90767, domain:4, level:2, question:"What distinguishes the IT security priority order from the typical OT security priority order?", options:["OT prioritizes confidentiality above all, while IT places availability as its single most important goal","Both IT and OT rank the three CIA pillars in exactly the same order under every recognized framework today","OT typically prioritizes availability and safety first, whereas IT usually prioritizes confidentiality first","OT ignores integrity entirely because process data accuracy is never relevant to physical plant safety at all"], correct:2, explanation:"OT flips the priority to availability/safety first vs IT's confidentiality focus; integrity remains critical to OT, not ignored." },
  { id:90768, domain:4, level:3, question:"A tester discovers an engineering workstation with project files for PLC ladder logic. Why is this significant?", options:["It proves the plant is fully patched, since only current systems retain accessible engineering project files","It is harmless because ladder logic project files are encrypted with keys stored only inside each PLC chip","It matters only for compliance paperwork and offers no path to influencing the physical process at all ever","It can allow the attacker to understand, modify, and download malicious logic to the controllers directly"], correct:3, explanation:"Access to project files lets an attacker alter and push malicious logic to PLCs; the files are not proof of patching or harmless." },
  { id:90769, domain:4, level:1, question:"Which command-line tool from the aircrack-ng suite puts an adapter into monitor mode and manages interfaces?", options:["airmon-ng, which enables monitor mode on a wireless interface and manages conflicting background processes","airodump-ng, which captures and displays frames but does not itself toggle the adapter into monitor mode","aircrack-ng, which performs the offline key cracking step and has nothing to do with interface mode changes","aireplay-ng, which injects frames such as deauth but relies on the interface already being in monitor mode"], correct:0, explanation:"airmon-ng enables monitor mode and kills interfering processes; airodump captures, aircrack cracks, and aireplay injects." },
  { id:90770, domain:4, level:1, question:"Which aircrack-ng tool captures raw 802.11 frames and displays nearby access points and clients?", options:["airbase-ng, which is used to create fake access points rather than to scan and list the existing networks","airodump-ng, which scans channels to list access points and associated clients while writing capture files","airdecap-ng, which decrypts already-captured WEP or WPA traffic and does not perform live channel scanning","packetforge-ng, which crafts custom encrypted packets for injection instead of enumerating nearby networks"], correct:1, explanation:"airodump-ng scans and lists APs/clients while capturing; airbase creates fake APs, airdecap decrypts, and packetforge crafts packets." },
  { id:90771, domain:4, level:2, question:"What does the term 'handshake' specifically refer to when capturing WPA2 credentials?", options:["The initial DHCP discover and offer exchange the client performs after it has already fully associated","The TCP three-way SYN, SYN-ACK, ACK sequence the client uses to open its first application connection","The four EAPOL messages exchanged when a client authenticates and derives keys with the access point","The ARP request and reply pair the client sends to learn the default gateway hardware address on the LAN"], correct:2, explanation:"The WPA2 handshake is the four EAPOL messages during authentication; DHCP, TCP, and ARP exchanges are unrelated to key derivation." },
  { id:90772, domain:4, level:2, question:"Which of the following would MOST improve resistance to WPA2 handshake cracking?", options:["Hiding the SSID so the handshake frames can never be observed by any monitoring adapter nearby at all","Lowering the AP transmit power so attackers a few meters away cannot capture the handshake frames either","Changing the AP channel frequently so the captured handshake becomes cryptographically invalid over time","Using a long, random passphrase that is infeasible to recover through dictionary or brute-force guessing"], correct:3, explanation:"A long random passphrase defeats guessing; hiding SSID, lowering power, and hopping channels do not stop offline cracking of a captured handshake." },
  { id:90773, domain:4, level:2, question:"In BLE security, what does 'Just Works' pairing lack that makes it vulnerable to man-in-the-middle attacks?", options:["It provides no man-in-the-middle protection because there is no user-verified numeric or passkey comparison","It mandates out-of-band NFC exchange, which attackers exploit by cloning the tag from across the room quickly","It requires a 16-digit passkey entry that users routinely mistype, accidentally pairing with attackers instead","It enforces elliptic-curve authentication so strong that legitimate devices frequently fail to pair at all ever"], correct:0, explanation:"Just Works has no MITM protection since nothing is user-verified; the distractors wrongly describe OOB or passkey methods." },
  { id:90774, domain:4, level:2, question:"Which tool is commonly used to scan for and interact with BLE devices during a pen test?", options:["aircrack-ng, which is dedicated to cracking 802.11 WEP and WPA keys and cannot speak the BLE protocol","gatttool or bleah, which enumerate BLE services and characteristics and can read or write their values","sqlmap, which automates SQL injection against web application databases rather than probing BLE peripherals","john, which cracks captured password hashes offline and offers no capability to talk to BLE peripherals at all"], correct:1, explanation:"gatttool/bleah enumerate and manipulate BLE characteristics; aircrack, sqlmap, and john target Wi-Fi, web, and hashes." },
  { id:90775, domain:4, level:3, question:"What is the effect of an RFID relay attack against a passive keyless entry system?", options:["It permanently erases the credential stored on the token, denying the owner future access to the building","It reprograms the door controller firmware over the air to accept any arbitrary badge presented afterward","It extends the effective range between token and reader so a distant credential authenticates the reader","It floods the reader with random UIDs until it fails open, granting entry to anyone standing nearby then"], correct:2, explanation:"A relay attack bridges the distance so a far-away token authenticates; it does not erase tokens, reflash controllers, or flood UIDs." },
  { id:90776, domain:4, level:2, question:"Which NFC attack involves an attacker placing a reader close to a victim's card to read it without consent?", options:["Beaconing, where the card continuously advertises its balance so any passerby can subtract funds from it","Tunneling, where the attacker encapsulates NFC frames inside DNS queries to exfiltrate them over the internet","Rooting, where the attacker gains kernel privileges on the card onboard operating system to alter its data","Skimming, where a concealed reader captures data from a contactless card held nearby without the owner knowing"], correct:3, explanation:"NFC skimming reads a nearby card covertly; beaconing, tunneling, and rooting are not standard contactless-card attacks." },
  { id:90777, domain:4, level:1, question:"What is a key limitation of NFC that constrains but does not eliminate its attack surface?", options:["Its very short operating range of a few centimeters, which forces attackers to get physically close to the target","Its mandatory use of quantum key distribution, which makes any interception provably impossible in practice","Its reliance on the global GPS constellation, which lets defenders geofence every transaction precisely each time","Its requirement for a wired fiber connection between card and reader, removing all over-the-air exposure entirely"], correct:0, explanation:"NFC's few-centimeter range limits but does not remove risk; it does not use quantum crypto, GPS, or fiber." },
  { id:90778, domain:4, level:3, question:"Which characteristic of MQTT makes topic enumeration valuable to an attacker?", options:["Each topic is protected by a unique client certificate, so enumeration reveals only the certificate serials","Wildcard subscriptions let an attacker subscribe broadly and observe every topic published on the broker","Topics are stored in an append-only blockchain that cryptographically hides their names from subscribers","The broker rejects any subscription that does not name the exact full topic path, preventing discovery entirely"], correct:1, explanation:"MQTT wildcard subscriptions let an attacker observe all topics; the distractors describe controls MQTT does not inherently enforce." },
  { id:90779, domain:4, level:2, question:"What does the OWASP IoT category 'Insecure Ecosystem Interfaces' primarily concern?", options:["The mechanical strength of the plastic enclosure and whether it resists prying with common hand tools quickly","The ambient electromagnetic emissions of the device that might interfere with nearby medical equipment badly","Weaknesses in the web, backend API, cloud, or mobile interfaces that manage and communicate with the device","The color-coding scheme of the device status LEDs and whether it is accessible to colorblind operators fully"], correct:2, explanation:"Insecure ecosystem interfaces cover web/API/cloud/mobile weaknesses; enclosure strength, emissions, and LEDs are not this category." },
  { id:90780, domain:4, level:2, question:"Why is UART often the first hardware interface a tester probes on an unfamiliar IoT board?", options:["It always requires a signed vendor dongle to activate, guaranteeing a controlled and audited access path each time","It transmits only encrypted video that must be decoded before any textual console output becomes visible at all","It is physically inaccessible until the multilayer board is delaminated with specialized chemical etching first","It frequently exposes an unauthenticated boot log and interactive shell using only three easily identified pins"], correct:3, explanation:"UART commonly exposes an unauthenticated console via three pins; it does not need a dongle, carry video, or require delamination." },
  { id:90781, domain:4, level:3, question:"What is the risk of leaving a JTAG interface enabled on a production IoT device?", options:["An attacker with physical access can halt the CPU, dump firmware and secrets, and bypass software protections","The device will automatically encrypt its own storage, locking out the legitimate owner during normal use only","The JTAG port continuously broadcasts the device location over cellular, aiding only benign asset tracking work","The interface throttles the CPU to one megahertz, degrading performance but posing no security consequence"], correct:0, explanation:"An enabled JTAG lets an attacker dump firmware/secrets and bypass protections; it does not encrypt storage or broadcast location." },
  { id:90782, domain:4, level:2, question:"Which industrial protocol uses TCP port 502 by default?", options:["DNP3, which uses TCP port 20000 by default and is common in electric and water utility SCADA systems","Modbus TCP, which encapsulates the classic Modbus register operations over TCP using port 502 by default","EtherNet/IP, which uses TCP port 44818 and UDP 2222 for its implicit and explicit messaging traffic","S7comm, which communicates with Siemens SIMATIC controllers over TCP port 102 rather than port 502"], correct:1, explanation:"Modbus TCP defaults to port 502; DNP3 uses 20000, EtherNet/IP uses 44818, and S7comm uses 102." },
  { id:90783, domain:4, level:2, question:"What is a 'jump host' or 'jump server' role in a segmented OT architecture?", options:["An unmonitored bridge that flattens all VLANs so engineers can reach any controller without restriction ever","A field device that physically leaps between substations to deliver firmware on removable media by hand","A controlled gateway system that mediates and audits all remote access between IT zones and the OT network","A backup PLC that assumes control automatically the instant the primary controller experiences any fault"], correct:2, explanation:"A jump host mediates and audits IT-to-OT remote access; it is not an unmonitored bridge, a courier, or a backup PLC." },
  { id:90784, domain:4, level:2, question:"Which is a legitimate reason active vulnerability scanning is risky in OT environments?", options:["Modern PLCs are so robust that scanning them accelerates the process and improves overall plant throughput","Scanning automatically installs the latest firmware on every device, which auditors consider a compliance risk","OT switches convert scan traffic into control commands, which usefully documents the process for engineers","Legacy controllers may crash or enter fault states when they receive unexpected or malformed scan packets"], correct:3, explanation:"Legacy controllers can crash on unexpected scan traffic, so scanning is risky; the distractors falsely portray scanning as safe or beneficial." },
  { id:90785, domain:4, level:3, question:"What does 'defense in depth' mean when applied to an ICS environment following the Purdue model?", options:["Layering controls across each Purdue level so compromise of one zone does not immediately expose the process","Placing every industrial device on one flat network so a single firewall can inspect all traffic centrally","Relying solely on the physical air gap as the one and only barrier protecting the control network from IT","Encrypting corporate email so thoroughly that attackers cannot phish their way into the enterprise IT zone"], correct:0, explanation:"Defense in depth layers controls across Purdue levels; a flat network, sole air gap, or email encryption alone is not defense in depth." },
  { id:90786, domain:4, level:3, question:"A pen tester needs to identify OT assets without disrupting them. Which technique fits best?", options:["Sending crafted Modbus write requests to each address to see which devices change state in response fast","Passively parsing a SPAN port capture to fingerprint devices from their protocol traffic and identifiers","Power-cycling every controller and cataloging which ones fail to restart within the expected time window","Uploading new ladder logic to each PLC and observing which processes behave differently afterward each time"], correct:1, explanation:"Passive SPAN-port fingerprinting identifies assets without disruption; writes, power-cycling, and logic uploads all risk the process." },
  { id:90787, domain:4, level:2, question:"What is a common goal of firmware modification attacks on IoT devices?", options:["Reducing the device power consumption so its battery lasts longer, purely as a benefit to the device owner","Improving the device Wi-Fi range by rewriting the radio calibration tables for stronger transmission output","Implanting persistent backdoors or disabling security checks so the attacker retains long-term control","Adding accessibility features for visually impaired users by re-recording the device audio prompts entirely"], correct:2, explanation:"Firmware modification typically implants backdoors or disables protections; the distractors describe benign or beneficial changes." },
  { id:90788, domain:4, level:2, question:"Which statement about WPA3-Enterprise 192-bit mode is correct?", options:["It removes all authentication so that any client can connect, trading security for maximum ease of onboarding","It reverts to the WEP RC4 cipher to maintain backward compatibility with very old legacy client devices only","It disables encryption on the management plane to reduce CPU load on constrained access point hardware","It mandates stronger cryptographic suites intended for high-security networks such as government and defense"], correct:3, explanation:"WPA3-Enterprise 192-bit mandates stronger suites for high-security use; it does not remove auth, use WEP, or disable encryption." },
  { id:90789, domain:4, level:2, question:"What is the primary purpose of channel hopping in a tool like airodump-ng?", options:["To cycle across multiple channels so the tool can discover access points operating on different frequencies","To encrypt the capture file so that only the analyst who set the hopping pattern can later open it up","To physically move the antenna between rooms so distant networks fall within the adapter reception range","To rotate the attacker MAC address on every frame so the target access point cannot log a stable identity"], correct:0, explanation:"Channel hopping lets airodump-ng discover APs across frequencies; it does not encrypt captures, move antennas, or rotate MACs." },
  { id:90790, domain:4, level:3, question:"Which factor most directly determines how quickly a captured WPA2 handshake can be cracked?", options:["The physical distance between the attacker and the access point at the moment the handshake was captured","The strength and length of the passphrase relative to the attacker wordlist and hardware cracking throughput","The channel number the network was operating on when the four-way handshake frames were first observed","The brand of wireless chipset inside the client device that originally performed the key exchange with the AP"], correct:1, explanation:"Crack speed depends on passphrase strength versus wordlist and hardware; distance, channel, and client chipset are irrelevant offline." },
  { id:90791, domain:4, level:1, question:"What does the term 'attack surface' mean specifically in an IoT context?", options:["The painted exterior area of the device casing measured in square centimeters for durability testing only now","The total number of registered users in the vendor cloud portal across all deployed device fleets globally","The sum of all interfaces, protocols, services, and physical ports through which the device can be attacked","The amount of RAM the device firmware consumes at idle, which vendors publish for marketing comparison"], correct:2, explanation:"Attack surface is the totality of interfaces/protocols/ports exposed; it is not casing area, user counts, or RAM usage." },
  { id:90792, domain:4, level:2, question:"Which is an appropriate rules-of-engagement consideration before testing an OT network?", options:["Agreeing to run the noisiest possible scans during peak production to maximize the number of findings","Ensuring no operators are notified so the test perfectly simulates a surprise attack on live machinery","Committing to leave every discovered vulnerability exploited in place so defenders can study it later","Coordinating test windows with operations and defining hard stop conditions to protect safety and uptime"], correct:3, explanation:"OT ROE must coordinate windows and define stop conditions for safety; noisy peak scans, secrecy, and leaving exploits live are unsafe." },
  { id:90793, domain:4, level:2, question:"What is the significance of finding an exposed CoAP endpoint during IoT reconnaissance?", options:["It may allow unauthenticated resource discovery and commands if access controls were not properly configured","It guarantees the device uses mutual TLS, since CoAP cannot operate without a validated client certificate","It proves the device is fully patched, because only current firmware retains any CoAP capability at all now","It means the device is offline, as CoAP endpoints only respond after the device has powered completely down"], correct:0, explanation:"An exposed CoAP endpoint may permit unauthenticated discovery/commands; CoAP does not require mutual TLS and is unrelated to patch status." },
  { id:90794, domain:4, level:2, question:"Which best describes a deauthentication flood as a denial-of-service technique?", options:["Exhausting the DHCP address pool so newly arriving clients can never obtain an IP configuration lease at all","Repeatedly sending spoofed deauth frames so clients are continuously kicked off and cannot stay connected","Overloading the RADIUS server with authentication requests until it stops issuing any access tokens at all","Filling the access point ARP cache with bogus entries so it forwards frames to nonexistent destinations only"], correct:1, explanation:"A deauth flood spoofs deauth frames to keep kicking clients off; DHCP exhaustion, RADIUS overload, and ARP poisoning are different methods." },
  { id:90795, domain:4, level:3, question:"Why might a tester emulate IoT firmware rather than test on the physical device?", options:["Emulation is the only method that can ever reveal hardcoded credentials, which are invisible on real hardware","Emulation physically repairs damaged flash chips, restoring bricked devices to full working condition again","Emulation enables scalable, repeatable analysis and debugging without risking or being limited by scarce hardware","Emulation is legally required in every jurisdiction before any real IoT device may be examined by a tester"], correct:2, explanation:"Emulation gives scalable, repeatable analysis without hardware limits; it is not the only way to find secrets, nor a repair or legal mandate." },
  { id:90796, domain:4, level:3, question:"What does a Modbus 'read holding registers' request reveal to a pen tester?", options:["The administrative password of the engineering workstation that most recently programmed the controller","The full TLS certificate chain the controller presents when establishing encrypted management sessions","The list of Windows domain users who are permitted to log in to the plant's supervisory control server","The current values stored in the device registers, potentially exposing process variables and setpoints"], correct:3, explanation:"Reading holding registers exposes process values/setpoints; it does not reveal workstation passwords, TLS chains, or domain users." },
  { id:90797, domain:4, level:2, question:"Which statement about industrial protocol encryption is generally accurate for legacy OT?", options:["Many legacy industrial protocols were designed without encryption, transmitting commands and data in cleartext","All legacy industrial protocols mandate AES-256 encryption enforced at the hardware level by every vendor","Legacy industrial protocols rotate ephemeral session keys faster than modern TLS to resist interception","Legacy industrial protocols require quantum-resistant signatures on each frame before any device accepts it"], correct:0, explanation:"Legacy OT protocols often lack encryption and send cleartext; they do not mandate AES, rotating keys, or quantum signatures." },
  { id:90798, domain:4, level:2, question:"What is the purpose of a 'data diode' in an OT security architecture?", options:["To duplicate every control command and send copies to two redundant PLCs for automatic load balancing","To enforce strictly one-way data flow, allowing monitoring data out while blocking any inbound commands","To encrypt bidirectional traffic between the corporate ERP system and the plant historian continuously","To convert Modbus frames into DNP3 frames so mismatched devices can interoperate across utility networks"], correct:1, explanation:"A data diode allows one-way flow (out) while blocking inbound commands; it is not a duplicator, encryptor, or protocol translator." },
  { id:90799, domain:4, level:3, question:"Which of the following is a realistic outcome of a successful attack on an HMI?", options:["The attacker instantly gains root on every PLC because HMIs store all controller private keys in plaintext","The attacker permanently disables the laws of physics governing the process, halting production forever now","The attacker can send misleading displays or issue operator-level commands that affect the physical process","The attacker automatically patches every OT device on the network, improving the plant security posture"], correct:2, explanation:"Compromising an HMI can falsify displays or issue commands affecting the process; it does not auto-root PLCs or patch devices." },
  { id:90800, domain:4, level:2, question:"What is the main benefit of a wordlist tailored to the target when cracking WPA2 passphrases?", options:["It cryptographically weakens the captured handshake so that any four-character passphrase becomes valid","It forces the access point to disclose its passphrase directly rather than requiring any offline computation","It rewrites the client firmware so the device reconnects using a passphrase the attacker already chose","It concentrates guesses on likely candidates, dramatically improving success rate over generic brute force"], correct:3, explanation:"A tailored wordlist raises success by focusing on likely passphrases; it does not weaken the handshake, coerce disclosure, or reflash clients." },
  { id:90801, domain:4, level:1, question:"Which term describes an unauthorized wireless access point secretly connected to an internal wired network?", options:["A rogue access point, which bridges attacker or unauthorized wireless access into the protected wired LAN","A honeypot access point, which is a deliberately deployed decoy intended to attract and study attackers","A mesh access point, which is a sanctioned node that extends coverage by relaying to other authorized APs","A repeater access point, which merely amplifies an existing authorized signal to extend its physical range"], correct:0, explanation:"A rogue AP is unauthorized and bridges into the wired LAN; honeypots, mesh nodes, and repeaters are deliberate or sanctioned devices." },
  { id:90802, domain:4, level:2, question:"What should a tester check first when handed an IoT device with an unknown web interface?", options:["The precise silicon die revision of the main processor, obtainable only by decapping the chip with acid","Default and weak credentials plus common misconfigurations before attempting more complex exploitation","The exact resonant frequency of the onboard buzzer, measured with laboratory acoustic instrumentation","The manufacturing date encoded in the solder mask color, cross-referenced against a vendor pantone chart"], correct:1, explanation:"Checking default credentials and misconfigurations is the practical first step; die revision, buzzer frequency, and solder color are irrelevant." },
  { id:90803, domain:4, level:3, question:"Which of the following is characteristic of the KRACK attack's impact?", options:["It instantly recovers the network passphrase in plaintext from a single captured beacon frame offline now","It permanently disables the access point radio hardware, requiring physical replacement of the whole unit","It can allow decryption or replay of frames, and on some clients injection, by resetting the nonce values","It rewrites the RADIUS server database to add attacker accounts with full enterprise administrative rights"], correct:2, explanation:"KRACK enables decryption/replay (and sometimes injection) via nonce reset; it does not recover passphrases, brick hardware, or edit RADIUS." },
  { id:90804, domain:4, level:1, question:"Why do many IoT botnets succeed at scale?", options:["Every IoT device enforces unique hardware-bound certificates, which botnets forge with stolen root keys","IoT devices require physical presence to log in, so attackers recruit large teams to visit each unit alone","IoT firmware is formally verified and bug-free, so botnets must instead rely on zero-day silicon flaws only","Vast numbers of devices share weak default credentials that are trivially guessed and rarely changed later"], correct:3, explanation:"IoT botnets thrive on shared weak default credentials at scale; the distractors falsely claim strong per-device security." },
  { id:90805, domain:4, level:3, question:"What is the security implication of unauthenticated MQTT publish access?", options:["An attacker can publish forged messages that subscribing devices act on, potentially triggering physical actions","An attacker can only read retained messages but is cryptographically barred from ever influencing any device","An attacker gains nothing because subscribers ignore every message whose signature they cannot independently verify","An attacker merely increases broker log size, which is a storage nuisance without any control-plane consequence"], correct:0, explanation:"Unauthenticated publish lets an attacker inject commands subscribers act on; MQTT does not inherently sign messages to block this." },
  { id:90806, domain:4, level:3, question:"Which describes the relationship between WPA2-PSK and its four-way handshake regarding forward secrecy?", options:["The handshake uses ephemeral Diffie-Hellman so captured traffic can never be decrypted even with the key","Because the PMK is static per passphrase, capturing the handshake enables offline recovery of that key","Each handshake negotiates a brand-new passphrase, so old captures are cryptographically useless to attackers","The handshake rotates the PMK on every frame, making offline dictionary attacks mathematically impossible now"], correct:1, explanation:"WPA2-PSK's PMK is static per passphrase, so a captured handshake permits offline cracking; it lacks per-frame PMK rotation or DH forward secrecy." },
  { id:90807, domain:4, level:1, question:"What is the role of a historian in a SCADA system?", options:["A field controller that directly executes ladder logic to actuate valves and motors in the plant process","A firewall appliance placed at the plant boundary to inspect all inbound traffic from the corporate network","A database that records time-series process data for trending, analysis, and regulatory reporting over time","A wireless access point that provides roaming connectivity to operators walking the plant floor with tablets"], correct:2, explanation:"A historian stores time-series process data for analysis/reporting; it is not a controller, firewall, or access point." },
  { id:90808, domain:4, level:3, question:"Which is a realistic first objective when a tester gains a foothold on an IoT device shell?", options:["Immediately soldering new components onto the board to permanently upgrade the device processor speed now","Rewriting the device marketing firmware banner to display a humorous message for the next customer to see","Physically shredding the flash chip to guarantee the evidence of access is destroyed before reporting it","Enumerating running services, credentials, and network reach to plan lateral movement into the wider network"], correct:3, explanation:"The first objective is enumerating services/credentials/reach for lateral movement; soldering, banner edits, and shredding are not." },
  { id:90809, domain:4, level:2, question:"Why is segmentation between IT and OT networks emphasized in ICS security guidance?", options:["It limits an attacker who compromises the IT side from pivoting directly into safety-critical control systems","It ensures OT devices receive firmware updates faster by giving them a dedicated high-bandwidth internet link","It merges the two networks so a single administrator can manage every device from one unified console easily","It exposes the control network to the internet so remote vendors can troubleshoot without any restrictions"], correct:0, explanation:"Segmentation limits pivoting from IT into OT; it does not speed updates, merge networks, or expose control systems to the internet." },
  { id:90810, domain:4, level:3, question:"What does 'Pixie Dust' fundamentally rely on to break WPS offline?", options:["Guessing the eight-digit PIN online at high speed against an access point that never enforces any lockout","Recovering the E-S1 and E-S2 secret nonces from an access point that generates them with weak randomness","Decrypting the WPA2 group key using a rainbow table precomputed for every possible SSID name in advance","Flooding the registrar with association requests until it discloses the PIN to relieve processing pressure"], correct:1, explanation:"Pixie Dust recovers weakly-generated nonces to derive the PIN offline; it is not online guessing, group-key decryption, or flooding." },
  { id:90811, domain:4, level:3, question:"Which is the safest way to test whether an OT protocol like Modbus is exposed on a network?", options:["Sending a burst of write requests to every possible unit ID to force each device to reveal its identity fast","Repeatedly resetting connections to the controller to measure how quickly it reestablishes the process loop","Passively observing existing traffic on a mirror port to confirm the protocol is present without sending packets","Uploading test logic to the controller to see whether the Modbus stack accepts unauthenticated programming"], correct:2, explanation:"Passive observation confirms exposure without risk; writes, resets, and logic uploads can disrupt fragile OT devices." },
  { id:90812, domain:4, level:2, question:"Which 802.11 frame category includes beacons, probe requests, and deauthentication frames?", options:["Data frames, which carry the actual user payload and are always encrypted under WPA2 regardless of settings","Control frames, which coordinate medium access with RTS, CTS, and acknowledgements but carry no discovery data","Extension frames, a category reserved for future amendments that current access points never actually transmit","Management frames, which handle association, discovery, and disconnection and are unauthenticated without 802.11w"], correct:3, explanation:"Beacons, probes, and deauths are management frames; data frames carry payload, control frames coordinate access, and extension frames are unused here." },
  { id:90813, domain:4, level:2, question:"What is the benefit of using a high-gain directional antenna during a wireless assessment?", options:["It extends usable range and focuses reception toward a specific target while rejecting off-axis interference","It automatically decrypts WPA3 traffic by concentrating enough radio energy to overwhelm the cipher itself","It converts the adapter into a rogue RADIUS server capable of authenticating enterprise clients directly now","It rewrites the SSID of nearby networks so victims connect to the tester access point by mistake instead"], correct:0, explanation:"A directional antenna extends range and focuses on a target; it cannot decrypt WPA3, act as RADIUS, or rewrite SSIDs." },
  { id:90814, domain:4, level:1, question:"Which is a defining trait of an open wireless network from a security standpoint?", options:["It uses WPA3 SAE by default, encrypting every frame while still allowing anyone to join without a password","It provides no link-layer encryption, so any nearby device can passively read the transmitted frames easily","It authenticates each client with a certificate but leaves the payload entirely unencrypted on the air waves","It rotates a shared WEP key hourly, which prevents passive eavesdropping despite requiring no passphrase"], correct:1, explanation:"Open networks have no link-layer encryption, so frames are readable; they do not use SAE, certificates, or rotating WEP keys." },
  { id:90815, domain:4, level:2, question:"What is the value of extracting and mounting an IoT device's SquashFS root filesystem?", options:["It physically repairs corrupted flash sectors, restoring a bricked device to normal factory operation again","It encrypts the firmware so competitors cannot reverse engineer the vendor proprietary algorithms later on","It exposes configuration files, binaries, and scripts that may contain secrets and exploitable logic inside","It measures the device power consumption profile, which is unrelated to any software vulnerability review"], correct:2, explanation:"Mounting the root filesystem exposes configs, binaries, and secrets; it does not repair flash, encrypt firmware, or measure power." },
  { id:90816, domain:4, level:2, question:"Why are hardcoded API tokens in IoT firmware a serious finding?", options:["The tokens only work while the specific device is powered on, so extraction yields nothing of lasting value","The tokens are per-user and change on every login, making an extracted copy immediately useless to attackers","The tokens are stored in a hardware enclave that erases them the moment the firmware image is copied off","Anyone extracting the firmware obtains a valid credential to the backend cloud service used by every device"], correct:3, explanation:"Hardcoded tokens grant backend access to anyone who extracts the firmware; they are not ephemeral, per-user, or enclave-protected." },
  { id:90817, domain:4, level:2, question:"Which is a realistic goal of analyzing MQTT topic structures on an IoT deployment?", options:["Mapping which devices publish sensor data and which subscribe to commands to understand the control flow","Recovering the WPA2 passphrase of the wireless network the broker happens to be connected through now","Decrypting TLS-protected web traffic from unrelated corporate applications on the same physical switch","Cracking the firmware signing key so a malicious update can be pushed to every device simultaneously"], correct:0, explanation:"Analyzing MQTT topics reveals publish/subscribe control flow; it does not recover Wi-Fi keys, decrypt TLS, or crack signing keys." },
  { id:90818, domain:4, level:2, question:"What is the primary risk of an internet-exposed HMI discovered via Shodan?", options:["The HMI will automatically apply security patches because Shodan indexing triggers a vendor update push","Remote attackers may view and manipulate the industrial process without ever entering the facility physically","The exposure improves availability by letting any engineer worldwide load-balance the control workload","The HMI encrypts itself the moment it is indexed, locking out both attackers and legitimate operators alike"], correct:1, explanation:"An internet-exposed HMI lets remote attackers view and manipulate the process; indexing does not patch, load-balance, or auto-encrypt it." },
  { id:90819, domain:4, level:3, question:"Which describes a correct precaution when testing near a running industrial process?", options:["Disabling every safety interlock first so the test can proceed without interference from protective systems","Running the most aggressive fuzzing available since OT hardware is immune to malformed input by design now","Having operations staff on standby with a defined rollback and emergency stop plan before any active test","Keeping the test entirely secret from operators so the process reaction appears completely natural to them"], correct:2, explanation:"Operations on standby with rollback and e-stop plans is correct; disabling interlocks, aggressive fuzzing, and secrecy are unsafe." },
  { id:90820, domain:4, level:3, question:"What makes DNP3 'secure authentication' (DNP3-SA) different from base DNP3?", options:["It replaces the entire protocol with HTTPS so that browsers can control substations directly and safely","It removes time-stamped events to reduce bandwidth, trading functionality for a marginal speed increase","It mandates that all traffic traverse the public internet so remote vendors can audit every command sent","It adds challenge-response authentication to verify commands, which base DNP3 entirely lacks by default"], correct:3, explanation:"DNP3-SA adds challenge-response authentication that base DNP3 lacks; it does not switch to HTTPS, drop events, or force internet transit." },
  { id:90821, domain:4, level:2, question:"What is a common purpose of a 'deauth' capability offered by tools like aireplay-ng in an assessment?", options:["Forcing associated clients to disconnect so a fresh WPA2 handshake can be captured for offline analysis","Permanently banning the client MAC address from the access point so it can never reassociate again later","Encrypting the captured frames with a session key so only the analyst can decrypt them after the test ends","Increasing the access point transmit power so distant clients produce stronger and cleaner capture frames"], correct:0, explanation:"Deauth disconnects clients to trigger a fresh handshake capture; it does not ban MACs, encrypt captures, or boost power." },
  { id:90822, domain:4, level:2, question:"Which best characterizes the OWASP IoT concern of 'Use of Insecure or Outdated Components'?", options:["Choosing enclosure plastics that degrade under UV light, weakening only the physical durability of the case","Reliance on deprecated libraries or unpatched OS components that carry known exploitable vulnerabilities","Selecting an unpopular color scheme that reduces the resale value of the device on secondary markets later","Bundling too many accessories in the retail box, which raises shipping costs without any security impact at all"], correct:1, explanation:"The concern is deprecated/unpatched components with known vulnerabilities; plastics, colors, and packaging are not security components." },
  { id:90823, domain:4, level:3, question:"What is a practical reason to capture a PMKID rather than a full handshake during a wireless test?", options:["It reveals the passphrase directly without any cracking, saving hours of offline computation on the wordlist","It works only against WPA3 SAE networks, which are otherwise completely immune to any offline attack method","It can be obtained from the access point alone, which is useful when no clients are currently connected to it","It requires flooding the AP with thousands of deauth frames, making it stealthier than a normal capture would be"], correct:2, explanation:"PMKID needs only the AP and no clients; it still requires offline cracking, works against WPA2, and does not need deauth flooding." },
  { id:90824, domain:4, level:1, question:"Which describes the security posture of most consumer IoT devices at their default factory settings?", options:["They enforce hardware-backed mutual TLS on every interface and disable all remote management by default now","They require a signed firmware update before any network interface will activate for the very first time ever","They come pre-enrolled in a zero-trust identity fabric that continuously verifies every request cryptographically","They frequently ship with open services, default credentials, and minimal hardening out of the box for the buyer"], correct:3, explanation:"Consumer IoT usually ships with open services and default credentials; strong TLS, mandatory signing, and zero-trust are not the norm." },
  { id:90825, domain:4, level:2, question:"A tester wants to map an IoT device's exposed network services. Which approach is most appropriate first?", options:["Running a port scan and banner grab against the device to enumerate listening services and their versions","Immediately fuzzing the device firmware update parser to trigger a crash before any enumeration is performed","Desoldering the flash chip and dumping it as the very first action before any network interaction whatsoever","Deauthenticating every nearby wireless client to force them onto the tester rogue access point for capture"], correct:0, explanation:"A port scan and banner grab is the appropriate first enumeration step; fuzzing, chip removal, and deauth are premature or unrelated here." },
  { id:90826, domain:4, level:3, question:"Which statement about Modbus and network segmentation is accurate for a defender?", options:["Because Modbus encrypts every frame with AES, segmentation adds no meaningful security value at all today","Because Modbus lacks authentication, restricting which hosts can reach it is a primary compensating control","Because Modbus authenticates each master with certificates, only network availability needs any protection","Because Modbus rotates session keys automatically, exposing it to the internet carries no additional risk now"], correct:1, explanation:"Modbus lacks authentication, so limiting reachable hosts is a key compensating control; it does not encrypt or authenticate frames." },
  { id:90827, domain:4, level:2, question:"Which BLE role describes a device that advertises and accepts connections, exposing its GATT services?", options:["The central role, which scans for advertisements and initiates connections rather than holding the database","The broadcaster role, which only transmits advertising data and never accepts any incoming connection at all","The peripheral role, which advertises and holds the GATT database that central devices connect to and query","The observer role, which only listens for advertisements and cannot initiate any connection whatsoever either"], correct:2, explanation:"The peripheral advertises and hosts the GATT database; central initiates, broadcaster only transmits, and observer only listens." },
  { id:90828, domain:4, level:2, question:"What is a key risk when an IoT device transmits sensor data over unencrypted HTTP?", options:["The device battery drains twice as fast, which is an availability concern but never a confidentiality one","The cloud backend automatically rejects the data, so no meaningful information is ever actually exposed","The transmission is limited to the local subnet by HTTP design, so remote interception is impossible outright","An on-path attacker can read and modify the telemetry, breaking both confidentiality and data integrity"], correct:3, explanation:"Unencrypted HTTP lets an on-path attacker read and alter telemetry; it is not a battery, rejection, or subnet-scope issue." },
  { id:90829, domain:4, level:2, question:"Which describes the WPS 'push button' method's weakness compared to the PIN method?", options:["It opens a short registration window during which any nearby device can associate without any credential","It requires the eight-digit PIN to be entered twice, doubling the brute-force keyspace the attacker faces","It cryptographically signs every association with the vendor root key, making it stronger than WPA3 itself","It disables the radio during registration, so no attacker can ever be present within range at that moment"], correct:0, explanation:"Push-button WPS opens a window any nearby device can join; it does not require a PIN, sign with a root key, or disable the radio." },
  { id:90830, domain:4, level:2, question:"What is the security value of enabling 802.11w Protected Management Frames on an enterprise WLAN?", options:["It encrypts the SSID inside beacons so attackers can no longer discover the network name from the air","It authenticates deauthentication and disassociation frames, mitigating spoofed disconnection attacks","It doubles the WPA2 key length to 512 bits, rendering all offline dictionary attacks computationally infeasible","It replaces the four-way handshake with a certificate exchange, removing the need for any pre-shared key at all"], correct:1, explanation:"802.11w authenticates management frames to stop spoofed disconnects; it does not hide SSIDs, lengthen keys, or replace the handshake." },
  { id:90831, domain:4, level:1, question:"Which industrial component directly interfaces with field sensors and actuators at the lowest control level?", options:["The enterprise resource planning server, which handles business logistics far above the process control level","The corporate domain controller, which authenticates office users and has no direct field device connections","The programmable logic controller, which reads sensor inputs and drives actuator outputs at the process level","The email gateway, which filters inbound messages and never interacts with any physical process equipment"], correct:2, explanation:"The PLC interfaces with field sensors/actuators at the control level; ERP, domain controllers, and email gateways are IT systems." },
  { id:90832, domain:4, level:3, question:"Which Purdue model level typically hosts SCADA supervisory control and HMIs?", options:["Level 0, the physical process level where the actual sensors and actuators physically touch the equipment","Level 5, the enterprise business network level where corporate email and ERP applications typically reside","Level 4, the site business planning level focused on logistics and scheduling rather than live process control","Level 2, the area supervisory control level where HMIs and supervisory systems monitor and manage the process"], correct:3, explanation:"Level 2 hosts supervisory control and HMIs; Level 0 is the physical process and Levels 4/5 are business/enterprise networks." },
  { id:90833, domain:4, level:3, question:"What is a realistic consequence of an attacker gaining write access to a PLC in a water treatment plant?", options:["They could alter setpoints for chemical dosing, creating a genuine safety hazard to the treated water supply","They could improve process efficiency automatically, which plant engineers would generally welcome as helpful","They could only read historical trend data, since PLCs never accept any write operations from the network at all","They could rewrite the corporate payroll system, because PLCs directly control all enterprise financial records"], correct:0, explanation:"PLC write access can alter dosing setpoints creating safety hazards; it is not benign, read-only, or connected to payroll." },
  { id:90834, domain:4, level:2, question:"Which best describes the purpose of firmware 'entropy analysis' during IoT assessment?", options:["It measures the physical temperature of the flash chip to determine whether the device was recently powered","High entropy regions can indicate encryption or compression, guiding where to focus extraction efforts next","It counts the number of solder joints on the board to estimate the manufacturing cost of the device unit","It calculates the exact retail price of the device by hashing the vendor logo stored inside the firmware"], correct:1, explanation:"Entropy analysis flags encrypted/compressed regions to guide extraction; it does not measure temperature, joints, or price." },
  { id:90835, domain:4, level:2, question:"Which is a correct reason WPA2-Enterprise is generally stronger than WPA2-Personal?", options:["It disables encryption entirely, trading confidentiality for far simpler and faster client onboarding overall","It relies on a single shared passphrase for all users, which is easier to rotate than individual credentials","It uses per-user 802.1X authentication so compromising one credential does not expose a shared network key","It broadcasts each user password in the clear so the RADIUS server can verify it without any computation"], correct:2, explanation:"WPA2-Enterprise uses per-user 802.1X so one credential's loss does not expose a shared key; the distractors describe weaker or false behavior." },
  { id:90836, domain:4, level:3, question:"What does capturing traffic on a mirrored switch port let an OT pen tester do safely?", options:["Actively rewrite Modbus commands in transit, which the mirror port conveniently forwards to controllers","Physically power down controllers on demand, since mirror ports carry control authority to the devices too","Automatically patch every device it observes, because mirroring implies a management channel to each host","Passively fingerprint devices and protocols from real traffic without injecting anything onto the network"], correct:3, explanation:"A mirror port enables passive fingerprinting without injection; it does not rewrite traffic, power devices, or patch them." },
  { id:90837, domain:4, level:2, question:"Which is a plausible outcome of successfully cloning an employee's 13.56 MHz RFID access card?", options:["The attacker can present the cloned card to gain physical entry wherever the original badge is authorized","The attacker instantly gains domain administrator rights on the corporate Active Directory environment there","The attacker decrypts all of the employee's email, because badge data doubles as their mailbox private key","The attacker disables the building fire suppression system, since access badges directly control that hardware"], correct:0, explanation:"A cloned badge grants physical entry where the original is authorized; it does not grant AD rights, decrypt email, or control fire systems." },
  { id:90838, domain:4, level:1, question:"What is a primary reason default credentials remain a top IoT problem despite being well known?", options:["Modern devices cryptographically prevent any login until the default password is changed, which never happens","Many devices lack a forced password-change step, and users rarely change defaults after installation completes","Default credentials are unique per device and printed nowhere, so no attacker could ever guess them anyway","Vendors rotate the default credentials remotely every hour, so any captured value expires before it is used"], correct:1, explanation:"Devices often lack forced changes and users leave defaults; they are not force-changed, unique-and-secret, or rotated hourly." },
  { id:90839, domain:4, level:2, question:"Which describes a legitimate use of Shodan filters during authorized IoT reconnaissance?", options:["Automatically exploiting every device it returns, since Shodan includes a built-in one-click attack launcher","Decrypting HTTPS traffic of any listed host, because Shodan caches the private keys of indexed web servers","Searching by product banner, port, or country to locate specific exposed device types within an agreed scope","Physically relocating listed devices, as Shodan integrates with shipping carriers to move hardware on request"], correct:2, explanation:"Shodan filters locate exposed device types by banner/port/country; it does not exploit, decrypt keys, or move hardware." },
  { id:90840, domain:4, level:3, question:"What is the significance of an ICS device responding to an unauthenticated Modbus read on the internet?", options:["It proves the device is fully hardened, since only secure controllers respond to internet Modbus requests at all","It means the device encrypts all responses, so the exposure poses no confidentiality or integrity risk whatsoever","It confirms the device is offline, because a live controller would never answer an unauthenticated read request","It indicates a critical exposure where anyone can query the controller and potentially probe for writable points"], correct:3, explanation:"An internet-reachable Modbus response signals critical exposure; it is not proof of hardening, encryption, or being offline." },
  { id:90841, domain:4, level:2, question:"Which best explains why serial UART consoles frequently lack authentication on IoT devices?", options:["They are intended for manufacturing and debugging, and vendors often forget to disable them in production units","They are protected by a hardware fingerprint reader that most attackers cannot physically bypass in practice","They transmit only over encrypted fiber, so authentication was deemed unnecessary by the original designers","They require a rotating one-time password generated by a cloud service before any character can be entered"], correct:0, explanation:"UART consoles are debug interfaces left enabled in production; they are not fingerprint-gated, fiber-encrypted, or OTP-protected." },
  { id:90842, domain:4, level:2, question:"What is a realistic first step after identifying UART pins on an IoT board?", options:["Immediately applying twelve volts to the transmit pin to force the bootloader into a hidden recovery mode","Connecting a USB-to-serial adapter at the correct baud rate to read the boot log and reach a shell prompt","Desoldering the entire connector so the board can be shipped back to the vendor for warranty replacement","Broadcasting the pin voltages over Wi-Fi so a remote colleague can analyze them without touching the board"], correct:1, explanation:"Connecting a serial adapter at the right baud rate to read the console is the realistic step; over-volting or desoldering are wrong." },
  { id:90843, domain:4, level:2, question:"Which describes the risk of an IoT device that accepts unsigned firmware updates?", options:["The device becomes immune to malware because unsigned updates are always rejected by the secure boot chain","The device can only ever be updated in a vendor facility, so remote attackers face no realistic update path","An attacker who can deliver an update may install fully malicious firmware that the device trusts and runs","The device automatically reverts any update after one minute, so malicious firmware never persists on it at all"], correct:2, explanation:"Unsigned updates let an attacker install malicious firmware the device trusts; they are not rejected, facility-only, or auto-reverted." },
  { id:90844, domain:4, level:2, question:"What is a defining feature of the CoAP protocol compared to MQTT?", options:["CoAP requires a central broker for every message, while MQTT connects devices directly without any broker","CoAP mandates TLS on all traffic, while MQTT is defined to always operate in cleartext with no security ever","CoAP is a physical-layer radio standard, while MQTT is an application protocol layered on top of it directly","CoAP uses a request/response REST model over UDP, whereas MQTT uses a publish/subscribe model over TCP"], correct:3, explanation:"CoAP is request/response over UDP; MQTT is publish/subscribe over TCP with a broker. The distractors invert these facts." },
  { id:90845, domain:4, level:3, question:"Which is a valid reason to prefer passive techniques when first assessing an unfamiliar OT network?", options:["Active probes can crash sensitive legacy devices, so passive observation reduces the chance of process disruption","Passive techniques automatically patch every observed device, improving the security posture during the test","Active probes are illegal in all jurisdictions, whereas passive listening is always explicitly exempt from law","Passive techniques reveal the exact plaintext passwords of every device without any further analysis required"], correct:0, explanation:"Passive observation avoids crashing fragile OT devices; it does not patch, enjoy blanket legal exemption, or reveal passwords directly." },
  { id:90846, domain:4, level:2, question:"What does an attacker gain by capturing and analyzing an IoT device's cloud API traffic?", options:["The physical GPS coordinates of the cloud data center, which is the primary goal of most IoT assessments","Understanding of endpoints, tokens, and message formats that may reveal weak authentication or authorization","The ability to instantly rewrite the laws governing TLS, decrypting all internet traffic worldwide at once","A guaranteed root shell on the device, because observing API traffic always yields remote code execution"], correct:1, explanation:"Capturing cloud API traffic reveals endpoints, tokens, and formats exposing weak auth; it does not give data-center GPS or automatic RCE." },
  { id:90847, domain:4, level:2, question:"Which is an accurate statement about EtherNet/IP in industrial networks?", options:["It is a proprietary wireless mesh protocol used only by battery-powered agricultural soil moisture sensors","It is a consumer file-sharing protocol repurposed from home networks that has no industrial usage at all now","It is a widely used industrial protocol built on standard Ethernet, common in discrete manufacturing automation","It is a cryptographic handshake standard designed exclusively to secure Modbus over the public internet safely"], correct:2, explanation:"EtherNet/IP is a common Ethernet-based industrial protocol in manufacturing; it is not a wireless mesh, file-sharing, or crypto handshake." },
  { id:90848, domain:4, level:2, question:"What is the role of a supplicant in 802.1X wireless authentication?", options:["The access point hardware that forwards frames and never participates in the authentication exchange itself","The RADIUS server backend that stores user accounts and issues the final accept or reject decision each time","The physical antenna element that focuses the radio beam toward the client during the authentication phase","The client device software that provides credentials to the authenticator for verification by the RADIUS server"], correct:3, explanation:"The supplicant is the client providing credentials; the authenticator (AP) relays them and the RADIUS server decides." },
  { id:90849, domain:4, level:1, question:"Which is a realistic risk of an IoT camera with a hardcoded backdoor account in its firmware?", options:["Anyone who learns the backdoor credentials can access the live video feed of every device running that firmware","The camera will refuse to record any footage at all until the backdoor account is manually deleted by the user","The backdoor only functions during a lunar eclipse, so the practical exposure window is negligibly small overall","The account grants access solely to the vendor marketing team and cannot reach any camera functionality at all"], correct:0, explanation:"A hardcoded backdoor lets anyone with the credentials view every affected camera's feed; it is not eclipse-limited or marketing-only." },
  { id:90850, domain:4, level:3, question:"What is the primary defensive value of network segmentation between Purdue levels?", options:["It guarantees that no device ever needs a security patch because segmentation alone removes all vulnerabilities","It contains a breach to a single zone, forcing an attacker to overcome additional barriers to reach the process","It makes every device internet-reachable so remote vendors can always troubleshoot without any access controls","It automatically encrypts all legacy Modbus and DNP3 traffic without changing any of the existing controllers"], correct:1, explanation:"Segmentation contains breaches and forces attackers through more barriers; it does not remove patching needs, expose devices, or encrypt legacy traffic." },
  { id:90851, domain:4, level:3, question:"Which best describes a 'downgrade' concern in mixed WPA3/WPA2 transition mode networks?", options:["The network automatically upgrades every legacy client to WPA3, eliminating all backward compatibility issues","Transition mode disables encryption entirely so that both WPA2 and WPA3 clients connect without any protection","An attacker may force clients to fall back to WPA2, exposing them to the older offline dictionary attacks again","Transition mode forces all clients to WPA3 only, immediately disconnecting every device that lacks SAE support"], correct:2, explanation:"Transition mode risks forcing a WPA2 fallback exposing weaker attacks; it does not auto-upgrade clients or disable encryption." },
  { id:90852, domain:4, level:2, question:"What is a plausible impact of a successful deauthentication attack beyond enabling handshake capture?", options:["It permanently rewrites the passphrase stored on every associated client, locking them out until a factory reset","It silently upgrades the network to WPA3, which is why defenders sometimes deploy it as a hardening measure","It grants the attacker a wired connection into the core switch by exploiting the deauth frame payload directly","It can act as a denial of service, repeatedly knocking legitimate users off the wireless network they rely on"], correct:3, explanation:"Deauth attacks can be a DoS by repeatedly disconnecting users; they do not rewrite passphrases, upgrade security, or provide wired access." },
  { id:90853, domain:4, level:2, question:"Which describes a correct approach to testing MQTT authentication controls?", options:["Attempting to connect without credentials and to subscribe to wildcard topics to verify access is restricted","Physically desoldering the broker flash chip, because MQTT authentication is stored only in hardware memory","Deauthenticating the broker's Wi-Fi clients, since MQTT authentication depends entirely on the wireless layer","Cracking the WPA2 handshake, because MQTT topics are encrypted with the same key as the wireless network"], correct:0, explanation:"Testing MQTT auth means trying anonymous connects and wildcard subscriptions; it is unrelated to flash chips, deauth, or Wi-Fi keys." },
  { id:90854, domain:4, level:2, question:"What is the security relevance of an IoT device exposing a debug UART with a root shell?", options:["It is harmless because root shells over UART are always read-only and cannot change any device state at all","It grants an attacker with brief physical access full control to read secrets and modify device behavior","It only matters if the device also exposes HDMI, since UART alone provides no meaningful capability by itself","It automatically locks after the first login attempt, so an attacker gets at most one harmless command ever"], correct:1, explanation:"A root shell over UART gives an attacker full local control; it is not read-only, dependent on HDMI, or single-command locked." },
  { id:90855, domain:4, level:3, question:"Which is an accurate characterization of the Modbus protocol's addressing model for an attacker?", options:["Every Modbus request must include a valid RADIUS ticket, so unauthenticated addressing is impossible in practice","Modbus addresses are encrypted per session, so an attacker cannot correlate any address with a physical point","Function codes and register or coil addresses map directly to process points that reads and writes can affect","Modbus uses random ephemeral addresses that change each second, making targeted writes practically impossible"], correct:2, explanation:"Modbus function codes and register/coil addresses map to process points an attacker can read/write; it has no RADIUS, encryption, or random addressing." },
  { id:90856, domain:4, level:2, question:"What is a reasonable objective when reverse engineering an extracted IoT firmware binary?", options:["Determining the exact factory paint color of the device chassis from strings embedded in the binary image","Calculating the mechanical torque of the enclosure screws from data stored inside the firmware partition","Measuring the device antenna gain in decibels using only the compiled machine code without any hardware","Locating authentication routines and hardcoded secrets that could enable bypass or backend access later"], correct:3, explanation:"Reverse engineering targets auth routines and hardcoded secrets; paint color, screw torque, and antenna gain are not derivable goals." },
  { id:90857, domain:4, level:2, question:"Which best describes why OT environments often run end-of-life operating systems?", options:["Long equipment lifecycles and vendor certification tie software to hardware that may run for decades unchanged","OT operators legally must run the newest OS release within twenty-four hours of every vendor publication","End-of-life systems receive more frequent security patches than current systems, so operators prefer them","OT hardware physically rejects any operating system newer than the one shipped, enforced in the silicon itself"], correct:0, explanation:"OT runs EOL systems due to long lifecycles and certification constraints; the distractors state false requirements or benefits." },
  { id:90858, domain:4, level:2, question:"What is the value of a 'known-plaintext' style comparison when analyzing captured IoT protocol traffic?", options:["It instantly decrypts AES-256 traffic because knowing any plaintext trivially reveals the full symmetric key","Correlating repeated command patterns with observed device behavior helps infer the meaning of opaque fields","It physically resets the device to factory defaults, discarding all captured traffic before analysis begins","It broadcasts the captured traffic to the vendor, who then returns a full protocol specification by email reply"], correct:1, explanation:"Correlating command patterns with behavior helps infer field meaning; it does not break AES, reset devices, or fetch specs from vendors." },
  { id:90859, domain:4, level:3, question:"Which is a defensible reason to avoid aggressive fuzzing of live PLCs during an engagement?", options:["PLCs reward fuzzing by running faster afterward, which unfairly skews the plant efficiency benchmarks upward","Fuzzing is impossible against PLCs because they ignore all network input by default under every configuration","Malformed inputs can trip safety systems or crash controllers, risking real physical process disruption on site","Fuzzing automatically encrypts the controller, which the plant would then be unable to decrypt or operate again"], correct:2, explanation:"Fuzzing live PLCs can trip safety systems and crash controllers, risking disruption; the distractors are false claims." },
  { id:90860, domain:4, level:2, question:"What does a tester learn from an IoT device's mobile companion app during assessment?", options:["The precise silicon fabrication node of the device processor, which the app stores for warranty tracking only","The physical shipping weight of the device, which the app requires to render its user interface correctly first","The ambient humidity of the manufacturing plant, embedded so the app can adjust its color theme dynamically","Hardcoded endpoints, keys, and API logic that reveal how the app authenticates and controls the device"], correct:3, explanation:"The companion app can expose hardcoded endpoints, keys, and API logic; it does not reveal fab node, weight, or plant humidity." },
  { id:90861, domain:4, level:2, question:"Which is a correct statement about the relationship between IT and OT convergence and risk?", options:["Connecting previously isolated OT systems to IT networks expands the attack surface reaching physical processes","Convergence eliminates all OT risk because IT security tools automatically protect every connected controller","Convergence physically disconnects the process from any network, which is why it is called air-gap convergence","Convergence has no security implications because OT and IT protocols are mutually incompatible at every layer"], correct:0, explanation:"IT/OT convergence expands the attack surface toward physical processes; it does not eliminate risk, disconnect, or lack implications." },
  { id:90862, domain:4, level:2, question:"What is the purpose of extracting the bootloader from an IoT firmware image?", options:["Bootloaders store the device retail price, which is the primary artifact testers seek during assessments","Analyzing the boot process may reveal secure-boot weaknesses or recovery modes that allow code execution","Extracting the bootloader physically recharges the device battery so testing can continue for longer periods","The bootloader contains the vendor marketing slogan, which uniquely identifies counterfeit devices in the field"], correct:1, explanation:"Analyzing the bootloader can reveal secure-boot weaknesses or recovery modes; it does not store price, recharge, or hold slogans." },
  { id:90863, domain:4, level:2, question:"Which best describes a rogue access point deployed as part of a social-engineering wireless attack?", options:["An AP that legitimately extends the corporate WLAN after full approval from the network security team first","An AP that only serves DNS and cannot forward any web traffic, making credential capture impossible in practice","An AP broadcasting an enticing free-WiFi SSID to lure victims into connecting so their traffic can be captured","An AP configured with WPA3-Enterprise and mutual certificates specifically to keep unauthorized users out"], correct:2, explanation:"A luring free-WiFi SSID to capture victim traffic is a rogue/social-engineering AP; the distractors describe sanctioned or harmless setups." },
  { id:90864, domain:4, level:2, question:"What is the security concern with an IoT device that stores TLS private keys in world-readable files?", options:["World-readable key files are automatically encrypted by the kernel, so exposure carries no practical risk at all","The device will refuse to boot, meaning the misconfiguration is self-correcting and never reaches production units","Only the vendor can read the file because world-readable permissions apply exclusively to the manufacturer account","Any process or attacker with filesystem access can steal the key and impersonate the device or decrypt its traffic"], correct:3, explanation:"World-readable private keys can be stolen to impersonate the device or decrypt traffic; permissions are not auto-encrypted or vendor-only." },
  { id:90865, domain:4, level:2, question:"Which is an accurate description of the DNP3 protocol's typical deployment?", options:["It is widely deployed in electric utility and water SCADA systems to communicate between masters and outstations","It is a consumer smart-home protocol used only inside residential Bluetooth light bulbs and door sensors alone","It is a web application framework for building dashboards and has no role in field device communication at all","It is an email encryption standard applied to corporate messages and never touches any industrial network ever"], correct:0, explanation:"DNP3 serves utility/water SCADA between masters and outstations; it is not a smart-home, web, or email protocol." },
  { id:90866, domain:4, level:2, question:"What is the main reason a tester documents safety observations during an OT penetration test?", options:["Safety observations are required only to increase the page count of the report for billing purposes on the invoice","Findings can directly affect physical safety, so clear reporting helps operators prioritize risk to people and process","Safety in OT is identical to IT, so the documentation is a formality with no distinct operational meaning at all","Operators ignore safety findings entirely, so the documentation exists purely as a legal disclaimer for the tester"], correct:1, explanation:"OT findings can affect physical safety, so clear reporting helps prioritize risk to people/process; the distractors trivialize this." },
  { id:90867, domain:4, level:2, question:"Which describes an appropriate scope limitation when testing production ICS equipment?", options:["Running unrestricted destructive tests during peak production to obtain the most realistic possible results fast","Testing only the office printers, because ICS equipment is universally out of scope for every engagement type","Restricting active tests to maintenance windows or lab replicas to avoid disrupting live safety-critical operations","Requiring the plant to shut down permanently before any single packet may be sent to any controller at all"], correct:2, explanation:"Limiting active tests to maintenance windows or lab replicas is appropriate; unrestricted peak testing or permanent shutdown are extremes." },
  { id:90868, domain:4, level:3, question:"What is a realistic benefit of using a hardware SPI flash reader during IoT assessment?", options:["It automatically decrypts any encrypted firmware it reads, since SPI readers include a built-in key recovery unit","It recharges the device while reading, so the assessment never needs an external power supply for the board","It uploads the firmware to a public repository automatically, which is the intended purpose of every SPI reader","It lets a tester dump the flash contents directly, obtaining firmware even when no software extraction path exists"], correct:3, explanation:"An SPI reader dumps flash directly to obtain firmware; it does not decrypt, recharge, or auto-upload anything." },
  { id:90869, domain:4, level:2, question:"Which is an accurate statement about wireless intrusion detection systems (WIDS) in defense?", options:["They monitor the RF environment to detect rogue APs, deauth floods, and other anomalous wireless activity","They physically block all radio waves in the facility, guaranteeing that no wireless attack can ever reach clients","They replace the need for encryption entirely, since detecting attacks is equivalent to preventing all of them","They only function on wired Ethernet segments and have no visibility into any over-the-air wireless traffic at all"], correct:0, explanation:"A WIDS monitors RF to detect rogue APs and deauth floods; it does not block all radio, replace encryption, or only see wired traffic." },
  { id:90870, domain:4, level:1, question:"What is the key takeaway about IoT default credentials from incidents like large-scale IoT botnets?", options:["The botnets exploited a flaw in WPA3 SAE, which is why default credentials were irrelevant to their spread","Unchanged default logins on internet-exposed devices enabled automated mass compromise at enormous scale","The devices were compromised only through physical access, so remote default-credential abuse played no role","The incidents proved default credentials are safe as long as the device sits behind any consumer-grade router"], correct:1, explanation:"Mass IoT botnets abused unchanged default logins on exposed devices; they were not WPA3, physical-only, or router-mitigated." },
  { id:90871, domain:4, level:2, question:"Which best describes the tester's goal when enumerating BLE characteristics with read/write properties?", options:["Measuring the physical color temperature of the device LED, which BLE characteristics always encode precisely","Determining the shipping carrier used for the device, which is mandatory metadata in every BLE characteristic","Identifying values that can be read or altered to observe or influence the device's behavior and state","Recovering the WPA2 passphrase of the network, since BLE characteristics mirror the wireless key by design"], correct:2, explanation:"Enumerating readable/writable characteristics helps observe or influence device state; they do not encode LED color, shipping, or Wi-Fi keys." },
  { id:90872, domain:4, level:3, question:"What is a correct precaution before sending any active traffic to a discovered ICS device?", options:["Assuming every ICS device tolerates aggressive scanning, since industrial hardware is built to be indestructible","Disabling the plant's safety instrumented system so the active traffic can reach the controller without interference","Publicly announcing the device IP so other researchers can test it simultaneously during the same live window","Confirming with stakeholders that the device is non-critical or that a maintenance window is in effect first"], correct:3, explanation:"Confirming non-criticality or a maintenance window is the right precaution; assuming indestructibility or disabling safety systems is dangerous." },
  { id:90873, domain:4, level:3, question:"Which describes the security implication of an IoT gateway that bridges Zigbee or Z-Wave to IP networks?", options:["A compromise of the gateway can expose or control all downstream low-power devices behind it on the network","The gateway physically isolates every device so that compromising it grants access to nothing beyond itself alone","The gateway encrypts the entire internet, so attacking it provides global decryption capability to the attacker","The gateway only forwards weather data and cannot influence any actuator, sensor, or downstream device at all"], correct:0, explanation:"Compromising the gateway can expose/control downstream devices; it does not isolate everything, encrypt the internet, or forward only weather." },
  { id:90874, domain:4, level:2, question:"What is a reasonable interpretation of finding Telnet open on an internet-facing industrial device?", options:["It is completely safe because Telnet encrypts all traffic with modern TLS by default on industrial hardware now","It is a serious exposure, since Telnet is unencrypted and often protected only by weak or default credentials","It indicates the device is patched, since only fully updated controllers keep the Telnet service enabled at all","It has no impact because Telnet cannot be reached across the internet due to a protocol-level design restriction"], correct:1, explanation:"Open Telnet on an internet-facing device is a serious exposure (unencrypted, weak creds); it is not TLS-encrypted, a patch indicator, or unreachable." },
  { id:90875, domain:4, level:3, question:"Which best explains why WPA2-PSK networks with weak passphrases remain vulnerable despite strong AES encryption?", options:["AES automatically strengthens any passphrase to 256 bits of entropy, so passphrase weakness is irrelevant entirely","AES transmits the passphrase in the clear during association, so the encryption strength never matters at all here","AES protects data in transit, but a weak passphrase can be recovered offline from a captured handshake by guessing","AES rotates the passphrase every minute, making the notion of a weak passphrase meaningless in modern networks"], correct:2, explanation:"Strong AES does not save a weak PSK, which is recoverable offline from a captured handshake; AES does not strengthen, transmit, or rotate the passphrase." },
  { id:90876, domain:4, level:3, question:"What is the purpose of a 'firmware diffing' technique across two IoT firmware versions?", options:["Diffing physically merges the two images into a faster combined firmware that improves device performance","Diffing recharges both devices simultaneously, which is why testers keep multiple firmware versions on hand","Diffing reveals the retail launch dates of each version, which is the only actionable output of the technique","Comparing versions reveals changed code that may indicate silently patched vulnerabilities worth investigating"], correct:3, explanation:"Firmware diffing surfaces changed code hinting at silent patches to investigate; it does not merge images, recharge, or reveal launch dates." },
  { id:90877, domain:4, level:3, question:"Which is an accurate description of a 'karma' style wireless attack against client devices?", options:["The rogue AP responds to client probe requests for any SSID, tricking devices into auto-connecting to it","The rogue AP refuses all probe requests, forcing clients to stay on their legitimate network for safety reasons","The rogue AP only accepts WPA3 clients with valid certificates, making it useless for luring ordinary devices","The rogue AP physically jams every channel so clients cannot connect to anything, including the rogue AP itself"], correct:0, explanation:"A karma attack answers probes for any SSID so clients auto-connect; it does not refuse probes, require certificates, or jam channels." },
  { id:90878, domain:4, level:2, question:"What is a correct reason to enumerate an IoT device's open UDP services in addition to TCP?", options:["UDP services are always encrypted, so scanning them is the only way to recover the device's cleartext credentials","Protocols like CoAP, SNMP, and some proprietary IoT services run over UDP and would be missed by TCP-only scans","UDP scanning physically powers the device, which is required before any TCP port can be enumerated afterward","UDP services are illegal to run on IoT devices, so finding any confirms the device is counterfeit and untrusted"], correct:1, explanation:"Many IoT services (CoAP, SNMP) use UDP and would be missed by TCP-only scans; UDP is not inherently encrypted, powering, or illegal." },
  { id:90879, domain:4, level:3, question:"Which best describes a safe way to validate a suspected OT vulnerability without impacting production?", options:["Exploiting the live controller during peak production, since that yields the most convincing proof for the report","Deleting the controller's firmware to confirm the device was vulnerable to unauthorized modification attempts","Reproducing the issue on an isolated lab replica or digital twin rather than exploiting the live system directly","Physically removing the device from the plant mid-operation to inspect it on a workbench during production hours"], correct:2, explanation:"Validating on an isolated lab replica or digital twin avoids production impact; live exploitation, firmware deletion, and removal are unsafe." },
  { id:90880, domain:4, level:2, question:"What is the relevance of the OWASP IoT concern 'Insufficient Privacy Protection' during testing?", options:["It concerns only the enclosure paint fading over time, which has no bearing on any user data whatsoever really","It is identical to insecure default passwords, so testing one automatically covers the other with no extra work","It applies solely to industrial controllers and never to consumer devices that handle personal information at all","Devices may collect and expose personal data without adequate safeguards, which testers should identify and report"], correct:3, explanation:"Insufficient privacy protection is about exposing personal data without safeguards; it is not about paint, identical to defaults, or industrial-only." },
  { id:90881, domain:4, level:3, question:"Which describes a valid reason segmentation and monitoring matter even in 'air-gapped' OT environments?", options:["Air gaps are often imperfect, so internal monitoring detects threats introduced by removable media or vendor links","Air gaps make monitoring impossible, so operators should remove all sensors and logging from the OT network","Air gaps guarantee zero threats, so any monitoring investment is wasted budget that should be reallocated to IT","Air gaps physically prevent electricity from reaching monitoring devices, which cannot function without a network"], correct:0, explanation:"Monitoring matters because air gaps are imperfect and threats enter via media/vendor links; the distractors deny monitoring value falsely." },
  { id:90882, domain:4, level:2, question:"What is a realistic outcome of identifying weak or absent authentication on an IoT device's REST API?", options:["The device becomes physically lighter, because unauthenticated APIs remove the need for a security coprocessor","An attacker could invoke device functions or read sensitive data directly by calling the API without credentials","The API automatically enrolls the attacker into a rewards program rather than exposing any device functionality","Nothing happens, because REST APIs on IoT devices are unreachable from any network by fundamental design rules"], correct:1, explanation:"Weak/absent API auth lets an attacker invoke functions or read data uncredentialed; the distractors are nonsensical or false." },
  { id:90883, domain:4, level:3, question:"Which is the most accurate statement about combining passive and active techniques in an OT engagement?", options:["Active destructive testing should always precede any passive work to establish a baseline of failed devices quickly","Passive and active techniques are mutually exclusive, so an engagement must choose exactly one and never both ever","Passive reconnaissance is typically performed first, with limited active testing added carefully under agreed controls","Active testing carries no more risk than passive listening, so the ordering between them is entirely irrelevant"], correct:2, explanation:"Passive recon usually comes first with careful, controlled active testing added; active work carries more OT risk and the two are complementary." },
  { id:90884, domain:4, level:2, question:"What does a captured WPA2 handshake fundamentally allow an attacker to attempt offline?", options:["Directly reading all future encrypted traffic in real time without ever recovering the passphrase at all first","Rewriting the access point configuration remotely, since the handshake includes administrative control frames","Instantly authenticating to the network, because the handshake itself is a reusable access token by design","Guessing candidate passphrases and testing each against the handshake until the correct key is finally found"], correct:3, explanation:"A captured handshake enables offline passphrase guessing; it is not a real-time decryptor, a config channel, or a reusable token." },
  { id:90885, domain:4, level:2, question:"Which is an accurate reason IoT devices are attractive pivot points inside a compromised network?", options:["They are often poorly monitored and trusted internally, letting an attacker move laterally toward higher-value systems","They contain the organization's entire financial database by default, making them the ultimate target directly","They automatically encrypt the whole network once compromised, which conveniently hides the attacker's activity","They cannot communicate with any other host, so compromising them provides no lateral movement value at all ever"], correct:0, explanation:"Poorly monitored, internally trusted IoT devices make good pivots for lateral movement; they do not hold all finances or block all communication." },
  { id:90886, domain:4, level:2, question:"What is a correct interpretation of finding an exposed MQTT broker with retained messages enabled?", options:["Retained messages are automatically encrypted per subscriber, so their exposure reveals nothing useful to attackers","An attacker may read the last published value on each topic, potentially learning sensitive device state or commands","Retained messages prove the broker is fully patched, since vulnerable brokers cannot retain any messages at all","Retained messages are visible only to the broker operator and are cryptographically hidden from every subscriber"], correct:1, explanation:"Retained messages let an attacker read the last value per topic, exposing state/commands; they are not per-subscriber encrypted or operator-only." },
  { id:90887, domain:4, level:1, question:"Which tool is specifically designed to read, clone, and emulate RFID and NFC tags during physical assessments?", options:["Wireshark, which decodes captured network packets on a computer but cannot interact with any RFID card at all","Burp Suite, which intercepts and modifies web application HTTP traffic rather than any contactless card signals","The Proxmark3, a versatile RFID/NFC research device able to read, clone, and emulate many card technologies","Aircrack-ng, which cracks 802.11 WEP and WPA keys and has no capability to read or emulate any RFID tag"], correct:2, explanation:"The Proxmark3 reads, clones, and emulates RFID/NFC tags; Wireshark, Burp, and aircrack-ng target packets, web traffic, and Wi-Fi." },
  { id:90888, domain:4, level:1, question:"What is the primary security purpose of Bluetooth pairing between two devices?", options:["Assigning each device a public IP address so they can be reached from anywhere across the wider internet","Increasing the radio transmit power so the two devices can maintain a connection across very long distances","Compressing all transferred files to reduce the airtime needed, with no bearing on any security property at all","Establishing a shared link key that authenticates the devices and encrypts their subsequent communication"], correct:3, explanation:"Pairing establishes a shared link key to authenticate and encrypt; it does not assign IPs, boost power, or compress files." },
  { id:90889, domain:4, level:2, question:"Which is an accurate description of a MAC address filtering control on a wireless access point?", options:["A weak control that attackers bypass by sniffing an allowed MAC and spoofing it, since MACs travel in cleartext","A strong cryptographic control that prevents any spoofing because MAC addresses are protected by the AES cipher","A control that encrypts the entire payload, making MAC filtering an adequate replacement for WPA2 encryption","A control that rotates each client MAC address hourly, so an attacker can never observe a valid value to spoof"], correct:0, explanation:"MAC filtering is weak because MACs are cleartext and easily spoofed; it does not encrypt payloads or rotate client MACs." },
  { id:90890, domain:4, level:2, question:"What does an attacker typically seek in an IoT device's NVRAM or configuration partition?", options:["The exact number of times the device has been powered on, which testers use to estimate its resale value now","Stored Wi-Fi passphrases, admin credentials, and API keys that persist across reboots in the writable partition","The vendor's stock ticker symbol, embedded so investors can track the manufacturer from within the firmware","The mechanical torque specification for the case screws, stored so field technicians can reassemble it later"], correct:1, explanation:"NVRAM/config often stores Wi-Fi passphrases, credentials, and keys; power-on counts, ticker symbols, and screw torque are not sought." },
  { id:90891, domain:4, level:2, question:"Which best explains why 802.11 open networks are unsafe for sensitive traffic even with a captive portal login?", options:["The captive portal encrypts every frame with WPA3, making any subsequent eavesdropping computationally infeasible","The captive portal replaces the need for TLS, so all application traffic is automatically protected end to end","The captive portal authenticates access but does not encrypt the air link, so traffic is still readable by sniffers","The captive portal forces all clients onto a private VLAN that no other wireless station can ever observe at all"], correct:2, explanation:"A captive portal gates access but leaves the air link unencrypted, so traffic is sniffable; it does not encrypt frames or replace TLS." },
  { id:90892, domain:4, level:3, question:"What is the significance of the Modbus function code 'read discrete inputs' to a pen tester?", options:["It rewrites the controller firmware, giving the attacker persistent code execution across every future reboot","It negotiates an encrypted session key with the controller so that later commands cannot be intercepted at all","It queries the plant's Active Directory to enumerate every engineer account that can log in to the workstation","It reveals the on/off state of digital inputs, exposing sensor and switch conditions in the monitored process"], correct:3, explanation:"Reading discrete inputs exposes digital sensor/switch states; it does not rewrite firmware, negotiate keys, or query AD." },
  { id:90893, domain:4, level:3, question:"Which is a realistic reason to test an IoT device's response to malformed CoAP or MQTT messages carefully?", options:["Malformed input may crash the device or reveal parsing flaws, but crashing a critical device can disrupt service","Malformed input always safely improves the device firmware, so aggressive fuzzing carries no downside whatsoever","Malformed input is ignored by every IoT device by design, so testing it provides no information of any value at all","Malformed input automatically encrypts the device, which is why testers use it as a hardening step in engagements"], correct:0, explanation:"Malformed input can crash devices or reveal parsing flaws, and crashing critical devices disrupts service; the distractors are false." },
  { id:90894, domain:4, level:2, question:"What does the presence of an unauthenticated SNMP service with a default community string indicate to a tester?", options:["The device is fully hardened, because only secure devices continue to run the SNMP protocol at all in production","The device may disclose configuration and allow changes via SNMP, since 'public' and 'private' are widely known","The SNMP traffic is encrypted end to end, so the default community string exposure has no practical consequence","The device has already been patched against every known vulnerability, which is why SNMP remains enabled on it"], correct:1, explanation:"Default SNMP community strings can disclose config and allow changes; SNMPv1/v2c is unencrypted and this is not a sign of hardening." },
  { id:90895, domain:4, level:2, question:"Which best describes a correct approach to assessing an OT network's exposure to the internet?", options:["Physically disconnecting every controller from power to see which internet services stop responding immediately","Uploading malicious ladder logic to each internet-facing PLC to confirm that the exposure is genuinely exploitable","Using search engines like Shodan and reviewing firewall rules to identify any control systems reachable externally","Deauthenticating the plant's wireless clients repeatedly until the control network reroutes itself over the internet"], correct:2, explanation:"Using Shodan and firewall-rule review identifies externally reachable control systems safely; the distractors are destructive or nonsensical." },
  { id:90896, domain:4, level:3, question:"What is a plausible impact of an attacker who compromises an industrial jump host used for remote maintenance?", options:["They immediately gain physical control of every actuator because jump hosts store the plant's mechanical blueprints","They can only view the corporate cafeteria menu, since jump hosts by definition never connect to any OT system","They automatically patch all downstream controllers, improving the plant security posture as a side effect entirely","They can leverage its authorized access to reach OT systems that are otherwise segmented from external networks"], correct:3, explanation:"A compromised jump host grants authorized access to segmented OT systems; it does not hold blueprints, avoid OT, or patch controllers." },
  { id:90897, domain:4, level:3, question:"Which statement about the WPA2 group temporal key (GTK) is accurate?", options:["It is a shared key used to protect broadcast and multicast traffic delivered to all associated clients at once","It is a unique per-user key that encrypts only the unicast traffic between a single client and the access point","It is the RADIUS shared secret used solely between the access point and the enterprise authentication server","It is the WPS PIN that authorizes a new station to join the network through push-button registration mode only"], correct:0, explanation:"The GTK protects broadcast/multicast traffic for all clients; the unicast key is the PTK, and RADIUS secrets and WPS PINs are unrelated." },
  { id:90898, domain:4, level:3, question:"What is a reasonable first action when a tester obtains a firmware image but binwalk finds no known filesystem?", options:["Concluding the firmware is empty and discarding it, since binwalk always identifies every possible filesystem type","Suspecting encryption or an unknown format and analyzing entropy and headers before attempting manual extraction","Immediately flashing the raw image back to the device to see whether it still boots without any modifications made","Assuming the device has no vulnerabilities, because firmware that binwalk cannot parse is inherently secure by design"], correct:1, explanation:"No binwalk match suggests encryption or an unknown format warranting entropy/header analysis; it is not empty, and unparseable does not mean secure." },
  { id:90899, domain:4, level:3, question:"Which describes the correct role of deauthentication in an evil-twin credential-harvesting attack chain?", options:["It permanently encrypts the victim device so that only the evil twin can ever communicate with it again afterward","It uploads the harvested credentials to the attacker automatically, replacing the need for any captive portal at all","It disconnects victims from the legitimate AP so they reconnect to the evil twin and reach the fake captive portal","It patches the legitimate access point so that the victim is forced to trust the evil twin's TLS certificate chain"], correct:2, explanation:"Deauth pushes victims off the real AP toward the evil twin's portal; it does not encrypt victims, upload creds, or patch the real AP." },
  { id:90900, domain:4, level:3, question:"What is an accurate consideration regarding safety when a Modbus write could actuate physical equipment?", options:["Modbus writes are always simulated by the controller and never affect physical equipment, so testing is fully risk-free","Modbus writes require a signed certificate that testers cannot produce, so the physical process can never be affected","Modbus writes only change historian records and can never reach any actuator, making safety review entirely unnecessary","Even a single test write may move a valve or motor, so testers must confirm it is safe before issuing any such command"], correct:3, explanation:"A Modbus write can actuate real equipment, so safety must be confirmed first; writes are not simulated, certificate-gated, or historian-only." },
];
